  function bindVirtualStick(stickEl, knobEl, onMove, onEnd) {
      let activePointerId = null;
      const radius = 48;
      function reset() {
          activePointerId = null;
          knobEl.style.left = '37px';
          knobEl.style.top = '37px';
          if (onEnd) onEnd();
      }
      function moveWithPointer(clientX, clientY) {
          const rect = stickEl.getBoundingClientRect();
          const cx = rect.left + rect.width * 0.5;
          const cy = rect.top + rect.height * 0.5;
          let dx = clientX - cx;
          let dy = clientY - cy;
          const dist = Math.hypot(dx, dy);
          if (dist > radius) {
              dx = (dx / dist) * radius;
              dy = (dy / dist) * radius;
          }
          knobEl.style.left = `${37 + dx}px`;
          knobEl.style.top = `${37 + dy}px`;
          onMove(dx / radius, dy / radius);
      }
      stickEl.addEventListener('pointerdown', (event) => {
          event.preventDefault();
          activePointerId = event.pointerId;
          if (stickEl.setPointerCapture) stickEl.setPointerCapture(event.pointerId);
          moveWithPointer(event.clientX, event.clientY);
      });
      stickEl.addEventListener('pointermove', (event) => {
          if (event.pointerId !== activePointerId) return;
          event.preventDefault();
          moveWithPointer(event.clientX, event.clientY);
      });
      const endHandler = (event) => {
          if (event.pointerId !== activePointerId) return;
          event.preventDefault();
          reset();
      };
      stickEl.addEventListener('pointerup', endHandler);
      stickEl.addEventListener('pointercancel', endHandler);
      stickEl.addEventListener('lostpointercapture', reset);
  }
