      const SEASON_QUEST_STAGE_COUNT = SEASON_QUEST_DEFS.length;

      function buildSeasonPassQuests() {
          return SEASON_QUEST_DEFS.map(def => ({
              id: def.id,
              kind: def.kind,
              stage: def.stage,
              title: def.title,
              desc: def.desc,
              target: def.target,
              xpReward: def.xpReward,
              rewards: Object.assign({}, def.rewards),
              progress: 0,
              completed: false,
              rewardClaimed: false
          }));
      }

      function resetSeasonPassForAll() {
          playerData.seasonPass = {
              seasonId: SEASON_PASS_ID,
              xp: 0,
              level: 1,
              premiumUnlocked: false,
              premiumUnlockedWith: '',
              claimedFreeRewards: [],
              claimedPremiumRewards: [],
              quests: {},
              questSchemaVersion: SEASON_PASS_SCHEMA_VERSION
          };
          for (const q of buildSeasonPassQuests()) {
              playerData.seasonPass.quests[q.id] = {
                  id: q.id,
                  kind: q.kind,
                  stage: q.stage,
                  progress: 0,
                  target: q.target,
                  title: q.title,
                  desc: q.desc,
                  completed: false,
                  rewardClaimed: false,
                  rewards: Object.assign({}, q.rewards || {}),
                  xpReward: q.xpReward
              };
          }
      }

      function ensureSeasonPassState() {
          if (!ENABLE_SEASON_QUESTS) return;
          if (!playerData.seasonPass || playerData.seasonPass.seasonId !== SEASON_PASS_ID) {
              resetSeasonPassForAll();
          }

          const pass = playerData.seasonPass;
          pass.questSchemaVersion = SEASON_PASS_SCHEMA_VERSION;
          if (!Array.isArray(pass.claimedFreeRewards)) pass.claimedFreeRewards = [];
          if (!Array.isArray(pass.claimedPremiumRewards)) pass.claimedPremiumRewards = [];
          if (!pass.quests || typeof pass.quests !== 'object') pass.quests = {};

          const seasonDefs = buildSeasonPassQuests();
          const validIds = new Set(seasonDefs.map(q => q.id));
          for (const q of seasonDefs) {
              const existing = pass.quests[q.id] || {};
              const existingProgress = Math.max(0, Math.floor(existing.progress || 0));
              const completed = !!existing.completed || existingProgress >= q.target;
              pass.quests[q.id] = {
                  id: q.id,
                  kind: q.kind,
                  stage: q.stage,
                  progress: completed ? q.target : Math.min(existingProgress, q.target),
                  target: q.target,
                  title: q.title,
                  desc: q.desc,
                  completed,
                  rewardClaimed: !!existing.rewardClaimed,
                  rewards: Object.assign({}, q.rewards || {}),
                  xpReward: q.xpReward
              };
          }

          for (const questId of Object.keys(pass.quests)) {
              if (!validIds.has(questId)) {
                  delete pass.quests[questId];
              }
          }
      }

      function resetSeasonPass() {
          resetSeasonPassForAll();
          saveProgress();
          updateEventBadge();
          updateQuestBadge();
      }

      function awardSeasonPassXp(amount = 0) {
          if (!ENABLE_SEASON_QUESTS) return false;
          ensureSeasonPassState();
          if (!amount || amount <= 0) return false;
          playerData.seasonPass.xp = (playerData.seasonPass.xp || 0) + amount;
          const level = Math.min(SEASON_PASS_MAX_LEVEL, Math.max(1, Math.floor((playerData.seasonPass.xp - 1) / SEASON_PASS_XP_PER_LEVEL) + 1));
          playerData.seasonPass.level = level;
          saveProgress();
          updateEventBadge();
          return true;
      }

      function progressSeasonPassQuest(questKey, amount = 1) {
          if (!ENABLE_SEASON_QUESTS) {
              return addDailyWeeklyQuestProgress(questKey, amount);
          }
          ensureSeasonPassState();
          const normalizedQuestKey = normalizeQuestKey(questKey);
          const pass = playerData.seasonPass;
          let q = pass.quests && pass.quests[normalizedQuestKey];
          if (!q && pass.quests) {
              const candidates = Object.values(pass.quests)
                  .filter(entry => !entry.completed && (entry.kind === normalizedQuestKey || entry.id === normalizedQuestKey) && isSeasonQuestStageUnlocked(pass, entry))
                  .sort((a, b) => (a.stage || 0) - (b.stage || 0));
              q = candidates[0];
          }
          if (!q || q.completed) return false;
          q.progress = (q.progress || 0) + amount;
          if (q.progress >= q.target) {
              q.progress = q.target;
              q.completed = true;
              awardSeasonPassXp(q.xpReward || 100);
          }
          saveProgress();
          updateEventBadge();
          return true;
      }

      function claimSeasonPassReward(tier) {
          if (!ENABLE_SEASON_QUESTS) return false;
          ensureSeasonPassState();
          const reward = SEASON_PASS_TIERS.find(entry => entry.tier === tier);
          if (!reward) return false;
          return claimSeasonPassTrackReward(tier, 'free');
      }

      function grantSeasonReward(reward) {
          if (!reward || !reward.type) return false;
          if (reward.type === 'coins') playerData.coins = (playerData.coins || 0) + (reward.amount || 0);
          else if (reward.type === 'souls') addSouls(reward.amount || 0);
          else if (reward.type === 'tapper') playerData.starrDrops = (playerData.starrDrops || 0) + (reward.amount || 0);
          else if (reward.type === 'eventTapper') {
              playerData.eventTappers = playerData.eventTappers || { common: 0, rare: 0, epic: 0, mythic: 0 };
              playerData.eventTappers.epic = (playerData.eventTappers.epic || 0) + (reward.amount || 0);
          } else if (reward.type === 'superTapper') playerData.superTapperCount = (playerData.superTapperCount || 0) + (reward.amount || 0);
          else if (reward.type === 'hyperTapper') playerData.hyperTapperCount = (playerData.hyperTapperCount || 0) + (reward.amount || 0);
          else if (reward.type === 'skin') {
              const skin = skinsDatabase[reward.id];
              if (!skin) return false;
              if (!playerData.ownedSkins[skin.brawler]) playerData.ownedSkins[skin.brawler] = [];
              if (!playerData.ownedSkins[skin.brawler].includes(skin.id)) playerData.ownedSkins[skin.brawler].push(skin.id);
              playerData.selectedSkins[skin.brawler] = skin.id;
          } else return false;
          return true;
      }

      function claimSeasonPassTrackReward(tier, track = 'free') {
          if (!ENABLE_SEASON_QUESTS) return false;
          ensureSeasonPassState();
          const pass = playerData.seasonPass;
          const rewardRow = SEASON_PASS_TIERS.find(entry => entry.tier === tier);
          if (!rewardRow) return false;
          if ((pass.level || 1) < tier) return false;
          const claimField = track === 'premium' ? 'claimedPremiumRewards' : 'claimedFreeRewards';
          if (!Array.isArray(pass[claimField])) pass[claimField] = [];
          if (pass[claimField].includes(tier)) return false;
          if (track === 'premium' && !pass.premiumUnlocked) return false;
          const reward = track === 'premium' ? rewardRow.premium : rewardRow.free;
          if (!grantSeasonReward(reward)) return false;
          pass[claimField].push(tier);
          saveProgress();
          updateEventBadge();
          updateQuestBadge();
          return true;
      }

      function claimSeasonQuestReward(questId) {
          if (!ENABLE_SEASON_QUESTS) return false;
          ensureSeasonPassState();
          const quest = playerData.seasonPass.quests?.[questId];
          if (!quest || !quest.completed || quest.rewardClaimed) return false;
          const rewards = quest.rewards || {};
          if (rewards.coins) playerData.coins = (playerData.coins || 0) + rewards.coins;
          if (rewards.gems) playerData.gems = (playerData.gems || 0) + rewards.gems;
          if (rewards.souls) addSouls(rewards.souls);
          if (rewards.tappers) playerData.starrDrops = (playerData.starrDrops || 0) + rewards.tappers;
          if (rewards.superTappers) playerData.superTapperCount = (playerData.superTapperCount || 0) + rewards.superTappers;
          if (rewards.hyperTappers) playerData.hyperTapperCount = (playerData.hyperTapperCount || 0) + rewards.hyperTappers;
          quest.rewardClaimed = true;
          saveProgress();
          updateEventBadge();
          updateQuestBadge();
          return true;
      }

      function unlockSeasonPremium(currency) {
          if (!ENABLE_SEASON_QUESTS) return false;
          ensureSeasonPassState();
          const pass = playerData.seasonPass;
          if (pass.premiumUnlocked) return false;
          if (currency === 'gems') {
              if ((playerData.gems || 0) < SEASON_PREMIUM_UNLOCK_GEMS) return false;
              playerData.gems -= SEASON_PREMIUM_UNLOCK_GEMS;
              pass.premiumUnlocked = true;
              pass.premiumUnlockedWith = 'gems';
          } else if (currency === 'coins') {
              if ((playerData.coins || 0) < SEASON_PREMIUM_UNLOCK_COINS) return false;
              playerData.coins -= SEASON_PREMIUM_UNLOCK_COINS;
              pass.premiumUnlocked = true;
              pass.premiumUnlockedWith = 'coins';
          } else {
              return false;
          }
          saveProgress();
          updateEventBadge();
          updateQuestBadge();
          return true;
      }

      function normalizeQuestKey(questKey) {
          const questAliases = {
              collect_coins_event: 'collect_cubes',
              use_tapper: 'perform_supers',
              get_kills: 'defeat_enemies',
              heal_allies: 'use_gadget',
              destroy_walls: 'deal_damage',
              deploy_fort: 'use_gadget'
          };
          return questAliases[questKey] || questKey;
      }

      const DAILY_WEEKLY_QUEST_SCHEMA_VERSION = 2;
