      const WEEKLY_QUESTS = [
          { id: 'weekly_stage_1', stage: 1, kind: 'play_match', title: 'Kickoff', desc: 'Play 4 matches.', target: 4, rewards: { coins: 200, souls: 8 } },
          { id: 'weekly_stage_2', stage: 2, kind: 'win_match', title: 'First Blood', desc: 'Win 2 matches.', target: 2, rewards: { coins: 230, souls: 10 } },
          { id: 'weekly_stage_3', stage: 3, kind: 'deal_damage', title: 'Arena Pressure', desc: 'Deal 30,000 damage.', target: 30000, rewards: { coins: 260, souls: 12 } },
          { id: 'weekly_stage_4', stage: 4, kind: 'defeat_enemies', title: 'Hunter Run', desc: 'Defeat 18 enemies.', target: 18, rewards: { coins: 290, souls: 14 } },
          { id: 'weekly_stage_5', stage: 5, kind: 'collect_cubes', title: 'Cube Surge', desc: 'Collect 25 power cubes.', target: 25, rewards: { coins: 320, souls: 16 } },
          { id: 'weekly_stage_6', stage: 6, kind: 'perform_supers', title: 'Super Flow', desc: 'Use 10 supers.', target: 10, rewards: { coins: 350, souls: 18 } },
          { id: 'weekly_stage_7', stage: 7, kind: 'use_gadget', title: 'Tech Master', desc: 'Use 8 gadgets.', target: 8, rewards: { coins: 380, souls: 20 } },
          { id: 'weekly_stage_8', stage: 8, kind: 'win_match', title: 'Clutch Time', desc: 'Win 4 matches.', target: 4, rewards: { coins: 430, souls: 24 } },
          { id: 'weekly_stage_9', stage: 9, kind: 'deal_damage', title: 'Damage Machine', desc: 'Deal 90,000 damage.', target: 90000, rewards: { coins: 500, souls: 30 } },
          { id: 'weekly_stage_10', stage: 10, kind: 'win_match', title: 'Final Push', desc: 'Win 7 matches to finish the weekly run.', target: 7, rewards: { coins: 600, gems: 2, souls: 40 } }
      ];
      const SOUL_STARTER_QUESTS = [
          { id: 'starter_play_1', kind: 'play_match', title: 'Soul Warmup', desc: 'Play 3 matches in any mode.', target: 3, rewards: { souls: 40 } },
          { id: 'starter_win_1', kind: 'win_match', title: 'Soul Victor', desc: 'Win 2 matches.', target: 2, rewards: { souls: 50 } },
          { id: 'starter_damage_1', kind: 'deal_damage', title: 'Soul Grinder', desc: 'Deal 30,000 total damage.', target: 30000, rewards: { souls: 60 } },
          { id: 'starter_super_1', kind: 'perform_supers', title: 'Soul Burst', desc: 'Use 8 supers.', target: 8, rewards: { souls: 50 } }
      ];
      const LIMITED_QUEST_EVENT_ID = 'ranked-rush-2026-05';
      const LIMITED_QUEST_DURATION_MS = 4 * 24 * 60 * 60 * 1000;
      const LIMITED_QUESTS = [
          { id: 'limited_ranked_5', kind: 'win_ranked', title: 'Ranked Push I', desc: 'Win 5 ranked battles.', target: 5, rewards: { coins: 1200, gems: 10, souls: 80 } },
          { id: 'limited_ranked_8', kind: 'win_ranked', title: 'Ranked Push II', desc: 'Win 8 ranked battles.', target: 8, rewards: { coins: 2200, gems: 20, souls: 150, hyperTappers: 1 } },
          { id: 'limited_play_3', kind: 'play_match', title: 'Warmup Sprint', desc: 'Play 3 matches in any mode.', target: 3, rewards: { coins: 650, souls: 45 } },
          { id: 'limited_damage_1', kind: 'deal_damage', title: 'Damage Storm', desc: 'Deal 120,000 total damage.', target: 120000, rewards: { coins: 1400, souls: 90, superTappers: 1 } }
      ];

      function getLocalDayKey(ts = Date.now()) {
          return new Date(ts).toDateString();
      }

      function getLocalWeekKey(ts = Date.now()) {
          const d = new Date(ts);
          d.setHours(0, 0, 0, 0);
          const day = (d.getDay() + 6) % 7;
          d.setDate(d.getDate() - day + 3);
          const firstThursday = new Date(d.getFullYear(), 0, 4);
          const firstDay = (firstThursday.getDay() + 6) % 7;
          firstThursday.setDate(firstThursday.getDate() - firstDay + 3);
          const week = 1 + Math.round((d - firstThursday) / (7 * 24 * 60 * 60 * 1000));
          return `${d.getFullYear()}-W${String(Math.max(1, week)).padStart(2, '0')}`;
      }

      function createQuestState(def) {
          return {
              id: def.id,
              stage: def.stage,
              kind: def.kind,
              title: def.title,
              desc: def.desc,
              target: def.target,
              progress: 0,
              completed: false,
              claimed: false,
              rewards: Object.assign({}, def.rewards)
          };
      }

      function buildQuestBucket(defs) {
          const bucket = {};
          for (const def of defs) {
              bucket[def.id] = createQuestState(def);
          }
          return bucket;
      }

      function createLimitedQuestMeta(startAt = Date.now()) {
          return {
              eventId: LIMITED_QUEST_EVENT_ID,
              startAt,
              endAt: startAt + LIMITED_QUEST_DURATION_MS
          };
      }

      function isLimitedQuestActive() {
          const meta = playerData.questBoard && playerData.questBoard.limitedMeta;
          if (!meta || !meta.endAt) return false;
          return Date.now() < meta.endAt;
      }

      function getLimitedQuestTimeLeftMs() {
          const meta = playerData.questBoard && playerData.questBoard.limitedMeta;
          if (!meta || !meta.endAt) return 0;
          return Math.max(0, meta.endAt - Date.now());
      }

      function formatLimitedQuestTimeLeft() {
          const left = getLimitedQuestTimeLeftMs();
          if (left <= 0) return 'Expired';
          const totalMinutes = Math.ceil(left / 60000);
          const days = Math.floor(totalMinutes / (24 * 60));
          const hours = Math.floor((totalMinutes % (24 * 60)) / 60);
          const mins = totalMinutes % 60;
          if (days > 0) return `${days}d ${hours}h left`;
          if (hours > 0) return `${hours}h ${mins}m left`;
          return `${mins}m left`;
      }

      function ensureDailyWeeklyQuestData() {
          if (!ENABLE_DAILY_WEEKLY_QUESTS) return;
          if (!playerData.questBoard || playerData.questBoard.schemaVersion !== DAILY_WEEKLY_QUEST_SCHEMA_VERSION) {
              playerData.questBoard = {
                  schemaVersion: DAILY_WEEKLY_QUEST_SCHEMA_VERSION,
                  dailyKey: getLocalDayKey(),
                  weeklyKey: getLocalWeekKey(),
                  daily: buildQuestBucket(DAILY_QUESTS),
                  weekly: buildQuestBucket(WEEKLY_QUESTS),
                  starter: buildQuestBucket(SOUL_STARTER_QUESTS),
                  limited: buildQuestBucket(LIMITED_QUESTS),
                  limitedMeta: createLimitedQuestMeta()
              };
              return;
          }
          if (!playerData.questBoard.daily) playerData.questBoard.daily = buildQuestBucket(DAILY_QUESTS);
          if (!playerData.questBoard.weekly) playerData.questBoard.weekly = buildQuestBucket(WEEKLY_QUESTS);
          if (!playerData.questBoard.starter) playerData.questBoard.starter = buildQuestBucket(SOUL_STARTER_QUESTS);
          if (!playerData.questBoard.limited) playerData.questBoard.limited = buildQuestBucket(LIMITED_QUESTS);
          if (!playerData.questBoard.limitedMeta || playerData.questBoard.limitedMeta.eventId !== LIMITED_QUEST_EVENT_ID) {
              playerData.questBoard.limitedMeta = createLimitedQuestMeta();
          }
      }

      function refreshDailyWeeklyQuests() {
          if (!ENABLE_DAILY_WEEKLY_QUESTS) return;
          ensureDailyWeeklyQuestData();
          const nowDay = getLocalDayKey();
          const nowWeek = getLocalWeekKey();
          if (playerData.questBoard.dailyKey !== nowDay) {
              playerData.questBoard.dailyKey = nowDay;
              playerData.questBoard.daily = buildQuestBucket(DAILY_QUESTS);
          }
          if (playerData.questBoard.weeklyKey !== nowWeek) {
              playerData.questBoard.weeklyKey = nowWeek;
              playerData.questBoard.weekly = buildQuestBucket(WEEKLY_QUESTS);
          }
          if (!isLimitedQuestActive()) {
              playerData.questBoard.limitedMeta = createLimitedQuestMeta();
              playerData.questBoard.limited = buildQuestBucket(LIMITED_QUESTS);
          }
      }

      function getQuestProgressCount(bucket) {
          if (!bucket) return 0;
          return Object.values(bucket).filter(q => q.completed && !q.claimed).length;
      }

      function isQuestStageUnlocked(bucketName, bucket, quest) {
          if (bucketName !== 'weekly' || !quest || typeof quest.stage !== 'number') return true;
          if (quest.stage <= 1) return true;
          const previousStageQuest = Object.values(bucket || {}).find(q => q.stage === quest.stage - 1);
          return !previousStageQuest || !!previousStageQuest.completed;
      }

      function getActiveWeeklyStage() {
          const weeklyBucket = playerData.questBoard && playerData.questBoard.weekly;
          if (!weeklyBucket) return 1;
          const staged = Object.values(weeklyBucket)
              .filter(q => typeof q.stage === 'number')
              .sort((a, b) => a.stage - b.stage);
          if (staged.length === 0) return 1;
          const active = staged.find(q => !q.completed);
          return active ? active.stage : WEEKLY_STAGE_COUNT;
      }

      function isSeasonQuestStageUnlocked(pass, quest) {
          if (!pass || !pass.quests || !quest || typeof quest.stage !== 'number') return true;
          if (quest.stage <= 1) return true;
          const previousStageQuest = Object.values(pass.quests).find(q => q.stage === quest.stage - 1);
          return !previousStageQuest || !!previousStageQuest.completed;
      }

      function getActiveSeasonQuestStage() {
          const pass = playerData.seasonPass;
          if (!pass || !pass.quests) return 1;
          const staged = Object.values(pass.quests)
              .filter(q => typeof q.stage === 'number')
              .sort((a, b) => a.stage - b.stage);
          if (staged.length === 0) return 1;
          const active = staged.find(q => !q.completed);
          return active ? active.stage : staged[staged.length - 1].stage;
      }

      function getClaimableSeasonRewardCount() {
          if (!ENABLE_SEASON_QUESTS || !playerData.seasonPass) return 0;
          const pass = playerData.seasonPass;
          const freeClaimed = new Set(pass.claimedFreeRewards || []);
          const premiumClaimed = new Set(pass.claimedPremiumRewards || []);
          const level = pass.level || 1;
          const freeReady = SEASON_PASS_TIERS.filter(t => t.tier <= level && !freeClaimed.has(t.tier)).length;
          const premiumReady = pass.premiumUnlocked ? SEASON_PASS_TIERS.filter(t => t.tier <= level && !premiumClaimed.has(t.tier)).length : 0;
          const questReady = Object.values(pass.quests || {}).filter(q => q.completed && !q.rewardClaimed).length;
          return freeReady + premiumReady + questReady;
      }

      function updateQuestBadge() {
          try {
              const el = document.getElementById('dailyWeeklyQuestCount');
              if (el && playerData.questBoard) {
                  const dailyReady = getQuestProgressCount(playerData.questBoard.daily);
                  const weeklyReady = getQuestProgressCount(playerData.questBoard.weekly);
                  const starterReady = getQuestProgressCount(playerData.questBoard.starter);
                  const limitedReady = isLimitedQuestActive() ? getQuestProgressCount(playerData.questBoard.limited) : 0;
                  const seasonReady = getClaimableSeasonRewardCount();
                  el.textContent = String(dailyReady + weeklyReady + starterReady + limitedReady + seasonReady);
              }
          } catch (e) {}
      }

      function progressSoulStarterQuests(questKey, amount = 1) {
          if (!ENABLE_DAILY_WEEKLY_QUESTS) return false;
          refreshDailyWeeklyQuests();
          const normalizedQuestKey = normalizeQuestKey(questKey);
          const bucket = playerData.questBoard.starter;
          if (!bucket) return false;
          const candidates = Object.values(bucket).filter(q => !q.completed && q.kind === normalizedQuestKey);
          if (candidates.length === 0) return false;
          const quest = candidates[0];
          quest.progress = (quest.progress || 0) + amount;
          if (quest.progress >= quest.target) {
              quest.progress = quest.target;
              quest.completed = true;
          }
          saveProgress();
          updateQuestBadge();
          return true;
      }

      function addDailyWeeklyQuestProgress(questKey, amount = 1) {
          if (!ENABLE_DAILY_WEEKLY_QUESTS) return false;
          refreshDailyWeeklyQuests();
          const normalizedQuestKey = normalizeQuestKey(questKey);
          let changed = false;
          for (const bucketName of ['daily', 'weekly']) {
              const bucket = playerData.questBoard[bucketName];
              if (!bucket) continue;
              const candidates = Object.values(bucket).filter(q => !q.completed && q.kind === normalizedQuestKey && isQuestStageUnlocked(bucketName, bucket, q));
              if (candidates.length === 0) continue;
              const quest = candidates[0];
              quest.progress = (quest.progress || 0) + amount;
              if (quest.progress >= quest.target) {
                  quest.progress = quest.target;
                  quest.completed = true;
              }
              changed = true;
          }
          if (changed) {
              saveProgress();
              updateQuestBadge();
          }
          if (progressSoulStarterQuests(normalizedQuestKey, amount)) changed = true;
          return changed;
      }

      function addLimitedQuestProgress(questKey, amount = 1) {
          if (!ENABLE_DAILY_WEEKLY_QUESTS) return false;
          refreshDailyWeeklyQuests();
          if (!isLimitedQuestActive()) return false;
          const normalizedQuestKey = normalizeQuestKey(questKey);
          const bucket = playerData.questBoard.limited;
          if (!bucket) return false;
          let changed = false;
          for (const quest of Object.values(bucket)) {
              if (!quest || quest.completed || quest.kind !== normalizedQuestKey) continue;
              quest.progress = (quest.progress || 0) + amount;
              if (quest.progress >= quest.target) {
                  quest.progress = quest.target;
                  quest.completed = true;
              }
              changed = true;
          }
          if (changed) {
              saveProgress();
              updateQuestBadge();
          }
          return changed;
      }

      function claimQuestReward(bucketName, questId) {
          if (!ENABLE_DAILY_WEEKLY_QUESTS) return false;
          refreshDailyWeeklyQuests();
          const bucket = playerData.questBoard[bucketName];
          const quest = bucket && bucket[questId];
          if (!quest || !quest.completed || quest.claimed) return false;
          const rewards = quest.rewards || {};
          if (rewards.coins) playerData.coins = (playerData.coins || 0) + rewards.coins;
          if (rewards.gems) playerData.gems = (playerData.gems || 0) + rewards.gems;
          if (rewards.souls) addSouls(rewards.souls);
          if (rewards.tappers) playerData.starrDrops = (playerData.starrDrops || 0) + rewards.tappers;
          if (rewards.superTappers) playerData.superTapperCount = (playerData.superTapperCount || 0) + rewards.superTappers;
          if (rewards.hyperTappers) playerData.hyperTapperCount = (playerData.hyperTapperCount || 0) + rewards.hyperTappers;
          quest.claimed = true;
          saveProgress();
          updateQuestBadge();
          return true;
      }

      function openQuestBoard() {
          if (!ENABLE_DAILY_WEEKLY_QUESTS) return;
          refreshDailyWeeklyQuests();
          ensureSeasonPassState();
          const overlay = document.createElement('div');
          overlay.style.position = 'fixed';
          overlay.style.inset = '0';
          overlay.style.background = 'rgba(8, 11, 20, 0.92)';
          overlay.style.zIndex = '1300';
          overlay.style.display = 'flex';
          overlay.style.alignItems = 'center';
          overlay.style.justifyContent = 'center';
          overlay.style.fontFamily = 'sans-serif';

          const panel = document.createElement('div');
          panel.style.width = 'min(1080px, 96vw)';
          panel.style.height = 'min(780px, 92vh)';
          panel.style.background = 'linear-gradient(180deg, #081523, #111826)';
          panel.style.border = '2px solid #5ec4ff';
          panel.style.borderRadius = '16px';
          panel.style.padding = '18px';
          panel.style.display = 'flex';
          panel.style.flexDirection = 'column';
          panel.style.gap = '12px';

          const top = document.createElement('div');
          top.style.display = 'flex';
          top.style.justifyContent = 'space-between';
          top.style.alignItems = 'center';
          const title = document.createElement('h1');
          title.textContent = 'Quest Hub';
          title.style.margin = '0';
          title.style.fontSize = '28px';
          title.style.color = '#8fd8ff';
          const close = document.createElement('button');
          close.textContent = 'Close';
          close.style.padding = '10px 14px';
          close.style.border = 'none';
          close.style.borderRadius = '8px';
          close.style.cursor = 'pointer';
          close.style.fontWeight = '700';
          close.style.background = '#5ec4ff';
          close.style.color = '#00111f';
          close.onclick = () => document.body.removeChild(overlay);
          top.appendChild(title);
          top.appendChild(close);

          const tabRow = document.createElement('div');
          tabRow.style.display = 'flex';
          tabRow.style.gap = '8px';
          tabRow.style.flexWrap = 'wrap';

          const content = document.createElement('div');
          content.style.flex = '1';
          content.style.minHeight = '0';
          content.style.overflow = 'hidden';

          function createColumn(columnTitle, subtitle, bucketName) {
              const bucket = playerData.questBoard[bucketName] || {};
              const column = document.createElement('div');
              column.style.background = 'rgba(6, 13, 24, 0.88)';
              column.style.border = '1px solid #2f4f70';
              column.style.borderRadius = '12px';
              column.style.padding = '12px';
              const header = document.createElement('div');
              header.innerHTML = `<div style="font-size:18px;font-weight:900;color:#c8ecff;">${columnTitle}</div><div style="font-size:12px;color:#95b8d4;">${subtitle}</div>`;
              column.appendChild(header);

              const orderedQuests = Object.values(bucket).sort((a, b) => {
                  if (typeof a.stage === 'number' && typeof b.stage === 'number') return a.stage - b.stage;
                  return 0;
              });
              for (const quest of orderedQuests) {
                  const row = document.createElement('div');
                  const questUnlocked = isQuestStageUnlocked(bucketName, bucket, quest);
                  const showInProgressLabel = bucketName === 'weekly' && typeof quest.stage === 'number';
                  const actionText = quest.claimed
                      ? 'Claimed'
                      : (quest.completed ? 'Claim' : (showInProgressLabel ? (questUnlocked ? 'In Progress' : 'Locked') : 'Locked'));
                  row.style.marginTop = '10px';
                  row.style.padding = '10px';
                  row.style.borderRadius = '10px';
                  row.style.border = quest.claimed ? '1px solid #4e6c85' : (quest.completed ? '1px solid #58e4b6' : (questUnlocked ? '1px solid #27405b' : '1px solid #1e2f44'));
                  row.style.background = quest.claimed ? 'rgba(54,75,95,0.25)' : (quest.completed ? 'rgba(88,228,182,0.08)' : (questUnlocked ? 'rgba(20,34,52,0.52)' : 'rgba(12,20,32,0.5)'));
                  const pct = Math.max(0, Math.min(100, Math.round(((quest.progress || 0) / Math.max(1, quest.target)) * 100)));
                  const reward = [];
                  if (quest.rewards?.coins) reward.push(`${quest.rewards.coins} Coins`);
                  if (quest.rewards?.gems) reward.push(`${quest.rewards.gems} Gems`);
                  if (quest.rewards?.souls) reward.push(`${quest.rewards.souls} Souls`);
                  if (quest.rewards?.tappers) reward.push(`${quest.rewards.tappers} Tapper Upper`);
                  row.innerHTML = `
                      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;">
                          <div>
                              <div style="font-weight:800;color:#d7ecff;">${typeof quest.stage === 'number' ? `Stage ${quest.stage} • ` : ''}${quest.title}</div>
                              <div style="font-size:12px;color:#89a9c7;margin-top:2px;">${quest.desc}</div>
                              <div style="font-size:11px;color:#ffda8f;margin-top:4px;">Reward: ${reward.join(' • ') || 'None'}</div>
                          </div>
                          <button style="padding:7px 10px;border:none;border-radius:8px;font-weight:800;cursor:${quest.completed && !quest.claimed ? 'pointer' : 'default'};background:${quest.claimed ? '#5f6f82' : (quest.completed ? '#58e4b6' : (questUnlocked ? '#2e4258' : '#1f2f42'))};color:#07111d;">${actionText}</button>
                      </div>
                      <div style="margin-top:8px;height:7px;background:#0b192b;border-radius:999px;overflow:hidden;">
                          <div style="height:100%;width:${pct}%;background:${quest.completed ? '#58e4b6' : '#5ec4ff'};"></div>
                      </div>
                      <div style="margin-top:4px;font-size:11px;color:#c1d8ee;">${quest.progress || 0}/${quest.target}</div>
                  `;
                  const claimButton = row.querySelector('button');
                  claimButton.onclick = () => {
                      if (claimQuestReward(bucketName, quest.id)) {
                          document.body.removeChild(overlay);
                          openQuestBoard();
                      }
                  };
                  column.appendChild(row);
              }
              return column;
          }

          function createCoreView() {
              const body = document.createElement('div');
              body.style.display = 'grid';
              body.style.gridTemplateColumns = 'repeat(3, minmax(0, 1fr))';
              body.style.gap = '14px';
              body.style.overflowY = 'auto';
              body.style.paddingRight = '4px';
              body.style.height = '100%';
              body.appendChild(createColumn('Daily Quests', `Resets: ${playerData.questBoard.dailyKey}`, 'daily'));
              body.appendChild(createColumn('Weekly Quests', `Resets: ${playerData.questBoard.weeklyKey} • Stage ${getActiveWeeklyStage()}/${WEEKLY_STAGE_COUNT}`, 'weekly'));
              body.appendChild(createColumn('Soul Starter', 'One-time • up to 200 free Souls', 'starter'));
              return body;
          }

          function createLimitedView() {
              const bucket = playerData.questBoard.limited || {};
              const body = document.createElement('div');
              body.style.height = '100%';
              body.style.overflowY = 'auto';
              body.style.paddingRight = '4px';

              const info = document.createElement('div');
              info.style.marginBottom = '12px';
              info.style.padding = '12px';
              info.style.borderRadius = '10px';
              info.style.border = '1px solid #5e46aa';
              info.style.background = 'linear-gradient(180deg, rgba(33,22,58,0.85), rgba(17,12,32,0.85))';
              info.innerHTML = `
                  <div style="font-size:18px;font-weight:900;color:#d5c7ff;">Limited Ranked Rush</div>
                  <div style="font-size:12px;color:#b7a9e7;margin-top:2px;">These quests are independent and can be completed in any order.</div>
                  <div style="font-size:12px;color:#ffd27a;margin-top:6px;">${formatLimitedQuestTimeLeft()}</div>
              `;
              body.appendChild(info);

              const orderedQuests = Object.values(bucket);
              for (const quest of orderedQuests) {
                  const row = document.createElement('div');
                  const active = isLimitedQuestActive();
                  const rewardClaimed = !!quest.claimed;
                  const done = !!quest.completed;
                  const claimable = active && done && !rewardClaimed;
                  const pct = Math.max(0, Math.min(100, Math.round(((quest.progress || 0) / Math.max(1, quest.target)) * 100)));
                  const reward = questRewardText(quest.rewards);
                  const actionText = rewardClaimed ? 'Claimed' : (claimable ? 'Claim' : (active ? 'In Progress' : 'Expired'));

                  row.style.marginBottom = '10px';
                  row.style.padding = '12px';
                  row.style.borderRadius = '10px';
                  row.style.border = rewardClaimed ? '1px solid #4e6c85' : (done ? '1px solid #58e4b6' : '1px solid #5e46aa');
                  row.style.background = rewardClaimed ? 'rgba(54,75,95,0.25)' : (done ? 'rgba(88,228,182,0.08)' : 'rgba(30,20,54,0.45)');
                  row.innerHTML = `
                      <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;">
                          <div>
                              <div style="font-weight:900;color:#e7dcff;">${quest.title}</div>
                              <div style="font-size:12px;color:#bcaee9;margin-top:2px;">${quest.desc}</div>
                              <div style="font-size:11px;color:#ffda8f;margin-top:4px;">Reward: ${reward}</div>
                          </div>
                          <button style="padding:7px 10px;border:none;border-radius:8px;font-weight:900;cursor:${claimable ? 'pointer' : 'default'};background:${rewardClaimed ? '#5f6f82' : (claimable ? '#58e4b6' : '#4a3c73')};color:#07111d;">${actionText}</button>
                      </div>
                      <div style="margin-top:8px;height:7px;background:#0b192b;border-radius:999px;overflow:hidden;">
                          <div style="height:100%;width:${pct}%;background:${done ? '#58e4b6' : '#b089ff'};"></div>
                      </div>
                      <div style="margin-top:4px;font-size:11px;color:#d0c4f2;">${quest.progress || 0}/${quest.target}</div>
                  `;
                  const claimButton = row.querySelector('button');
                  claimButton.onclick = () => {
                      if (!claimable) return;
                      if (claimQuestReward('limited', quest.id)) {
                          document.body.removeChild(overlay);
                          openQuestBoard();
                      }
                  };
                  body.appendChild(row);
              }
              return body;
          }

          function seasonTrackRewardText(reward) {
              if (!reward) return 'No reward';
              if (reward.type === 'coins') return `${reward.amount} Coins`;
              if (reward.type === 'souls') return `${reward.amount} Souls`;
              if (reward.type === 'tapper') return `${reward.amount} Tapper Upper`;
              if (reward.type === 'eventTapper') return `${reward.amount} Event Tappers`;
              if (reward.type === 'superTapper') return `${reward.amount} Super Tappers`;
              if (reward.type === 'hyperTapper') return `${reward.amount} Hyper Tappers`;
              if (reward.type === 'skin') return 'Exclusive Skin';
              return 'Reward';
          }

          function questRewardText(rewards) {
              const parts = [];
              if (rewards?.coins) parts.push(`${rewards.coins} Coins`);
              if (rewards?.gems) parts.push(`${rewards.gems} Gems`);
              if (rewards?.souls) parts.push(`${rewards.souls} Souls`);
              if (rewards?.tappers) parts.push(`${rewards.tappers} Tapper`);
              if (rewards?.superTappers) parts.push(`${rewards.superTappers} Super Tapper`);
              if (rewards?.hyperTappers) parts.push(`${rewards.hyperTappers} Hyper Tapper`);
              return parts.join(' • ') || 'None';
          }

          function createSeasonView() {
              const pass = playerData.seasonPass || {};
              const wrapper = document.createElement('div');
              wrapper.style.display = 'grid';
              wrapper.style.gridTemplateColumns = '0.95fr 1.25fr';
              wrapper.style.gap = '14px';
              wrapper.style.height = '100%';
              wrapper.style.minHeight = '0';

              const questBox = document.createElement('div');
              questBox.style.padding = '12px';
              questBox.style.border = '1px solid #304876';
              questBox.style.borderRadius = '12px';
              questBox.style.background = 'linear-gradient(180deg, #0b1628, #0a1220)';
              questBox.style.overflowY = 'auto';

              const questTitle = document.createElement('div');
              questTitle.textContent = `New Season Quests • Stage ${getActiveSeasonQuestStage()}/${SEASON_QUEST_STAGE_COUNT}`;
              questTitle.style.fontWeight = '900';
              questTitle.style.color = '#8fd8ff';
              questTitle.style.marginBottom = '6px';
              const questHint = document.createElement('div');
              questHint.textContent = 'Complete and claim each quest to push the ladder milestones.';
              questHint.style.fontSize = '11px';
              questHint.style.color = '#aac7e5';
              questHint.style.marginBottom = '10px';
              questBox.appendChild(questTitle);
              questBox.appendChild(questHint);

              const stagedQuests = buildSeasonPassQuests().sort((a, b) => a.stage - b.stage);
              for (const quest of stagedQuests) {
                  const questState = pass.quests?.[quest.id] || { progress: 0, target: quest.target, completed: false, rewardClaimed: false, stage: quest.stage };
                  const done = !!questState.completed;
                  const rewardClaimed = !!questState.rewardClaimed;
                  const unlocked = isSeasonQuestStageUnlocked(pass, questState);
                  const percent = Math.max(0, Math.min(100, Math.round((questState.progress || 0) / Math.max(1, quest.target) * 100)));
                  const questCard = document.createElement('div');
                  questCard.style.padding = '10px';
                  questCard.style.borderRadius = '10px';
                  questCard.style.marginBottom = '8px';
                  questCard.style.border = rewardClaimed ? '1px solid #58e4b6' : (done ? '1px solid #ffb15a' : (unlocked ? '1px solid #2f4f70' : '1px solid #1f2f42'));
                  questCard.style.background = rewardClaimed ? 'rgba(88,228,182,0.08)' : (done ? 'rgba(255,177,90,0.1)' : (unlocked ? 'rgba(20,34,52,0.52)' : 'rgba(12,20,32,0.45)'));
                  questCard.innerHTML = `
                      <div style="display:flex;justify-content:space-between;gap:8px;">
                          <div style="font-size:12px;font-weight:900;color:#d7ecff;">Stage ${quest.stage} • ${quest.title}</div>
                          <div style="font-size:11px;color:${rewardClaimed ? '#58e4b6' : (done ? '#ffb15a' : (unlocked ? '#8fd8ff' : '#7f97b2'))};font-weight:800;">${rewardClaimed ? 'Claimed' : (done ? 'Claim Ready' : (unlocked ? 'In Progress' : 'Locked'))}</div>
                      </div>
                      <div style="font-size:11px;color:#95b8d4;margin:4px 0 6px 0;line-height:1.3;">${quest.desc}</div>
                      <div style="font-size:11px;color:#ffda8f;margin-bottom:6px;">Quest Reward: ${questRewardText(questState.rewards || quest.rewards)}</div>
                      <div style="height:6px;border-radius:999px;overflow:hidden;background:#0d1c2c;">
                          <div style="height:100%;width:${percent}%;background:${rewardClaimed ? '#58e4b6' : (done ? '#ffb15a' : '#5ec4ff')};"></div>
                      </div>
                      <div style="margin-top:5px;font-size:11px;color:${rewardClaimed ? '#58e4b6' : '#c1d8ee'};font-weight:700;text-align:center;">${questState.progress || 0}/${quest.target}</div>
                  `;
                  const claimBtn = document.createElement('button');
                  claimBtn.textContent = rewardClaimed ? 'Claimed' : (done ? 'Claim Quest Reward' : 'Locked');
                  claimBtn.style.marginTop = '8px';
                  claimBtn.style.padding = '6px 10px';
                  claimBtn.style.width = '100%';
                  claimBtn.style.border = 'none';
                  claimBtn.style.borderRadius = '7px';
                  claimBtn.style.fontWeight = '800';
                  claimBtn.style.cursor = done && !rewardClaimed ? 'pointer' : 'default';
                  claimBtn.style.background = rewardClaimed ? '#5f6f82' : (done ? '#ffb15a' : '#2a3d54');
                  claimBtn.style.color = '#07111d';
                  claimBtn.onclick = () => {
                      if (!done || rewardClaimed) return;
                      if (claimSeasonQuestReward(quest.id)) {
                          document.body.removeChild(overlay);
                          openQuestBoard();
                      }
                  };
                  questCard.appendChild(claimBtn);
                  questBox.appendChild(questCard);
              }

              const ladderBox = document.createElement('div');
              ladderBox.style.padding = '12px';
              ladderBox.style.border = '1px solid #ff9b42';
              ladderBox.style.borderRadius = '12px';
              ladderBox.style.background = 'linear-gradient(180deg, #211109, #091120)';
              ladderBox.style.overflowY = 'auto';

              const ladderTitle = document.createElement('div');
              ladderTitle.textContent = 'Milestone Ladder';
              ladderTitle.style.fontWeight = '900';
              ladderTitle.style.color = '#ffd39a';
              ladderTitle.style.fontSize = '16px';
              const ladderSub = document.createElement('div');
              ladderSub.style.fontSize = '12px';
              ladderSub.style.color = '#ffd9c0';
              ladderSub.style.margin = '4px 0 10px 0';
              ladderSub.textContent = `Milestones unlocked: ${pass.level || 1}/${SEASON_PASS_MAX_LEVEL}`;
              ladderBox.appendChild(ladderTitle);
              ladderBox.appendChild(ladderSub);

              const unlockPanel = document.createElement('div');
              unlockPanel.style.border = '1px solid #3d2b18';
              unlockPanel.style.borderRadius = '10px';
              unlockPanel.style.padding = '10px';
              unlockPanel.style.marginBottom = '10px';
              unlockPanel.style.background = pass.premiumUnlocked ? 'rgba(88,228,182,0.08)' : 'rgba(33,17,9,0.55)';
              if (pass.premiumUnlocked) {
                  unlockPanel.innerHTML = `<div style="font-weight:900;color:#58e4b6;">Premium Track Unlocked</div><div style="font-size:11px;color:#c1d8ee;margin-top:4px;">Unlocked with ${pass.premiumUnlockedWith || 'premium currency'}.</div>`;
              } else {
                  const titleEl = document.createElement('div');
                  titleEl.textContent = 'Unlock Premium Track';
                  titleEl.style.fontWeight = '900';
                  titleEl.style.color = '#ffd39a';
                  titleEl.style.marginBottom = '6px';
                  const actions = document.createElement('div');
                  actions.style.display = 'flex';
                  actions.style.gap = '8px';
                  const gemBtn = document.createElement('button');
                  gemBtn.textContent = `${SEASON_PREMIUM_UNLOCK_GEMS} Gems`;
                  gemBtn.style.flex = '1';
                  gemBtn.style.padding = '7px 8px';
                  gemBtn.style.border = 'none';
                  gemBtn.style.borderRadius = '8px';
                  gemBtn.style.fontWeight = '900';
                  gemBtn.style.cursor = (playerData.gems || 0) >= SEASON_PREMIUM_UNLOCK_GEMS ? 'pointer' : 'not-allowed';
                  gemBtn.style.background = (playerData.gems || 0) >= SEASON_PREMIUM_UNLOCK_GEMS ? '#ffb15a' : '#596b7f';
                  gemBtn.onclick = () => {
                      if (unlockSeasonPremium('gems')) {
                          document.body.removeChild(overlay);
                          openQuestBoard();
                      }
                  };
                  const coinBtn = document.createElement('button');
                  coinBtn.textContent = `${SEASON_PREMIUM_UNLOCK_COINS} Coins`;
                  coinBtn.style.flex = '1';
                  coinBtn.style.padding = '7px 8px';
                  coinBtn.style.border = 'none';
                  coinBtn.style.borderRadius = '8px';
                  coinBtn.style.fontWeight = '900';
                  coinBtn.style.cursor = (playerData.coins || 0) >= SEASON_PREMIUM_UNLOCK_COINS ? 'pointer' : 'not-allowed';
                  coinBtn.style.background = (playerData.coins || 0) >= SEASON_PREMIUM_UNLOCK_COINS ? '#58e4b6' : '#596b7f';
                  coinBtn.onclick = () => {
                      if (unlockSeasonPremium('coins')) {
                          document.body.removeChild(overlay);
                          openQuestBoard();
                      }
                  };
                  actions.appendChild(gemBtn);
                  actions.appendChild(coinBtn);
                  unlockPanel.appendChild(titleEl);
                  unlockPanel.appendChild(actions);
              }
              ladderBox.appendChild(unlockPanel);

              const freeClaimed = new Set(pass.claimedFreeRewards || []);
              const premiumClaimed = new Set(pass.claimedPremiumRewards || []);
              const ladderList = document.createElement('div');
              for (const tier of SEASON_PASS_TIERS) {
                  const tierUnlocked = (pass.level || 1) >= tier.tier;
                  const freeDone = freeClaimed.has(tier.tier);
                  const premiumDone = premiumClaimed.has(tier.tier);

                  const row = document.createElement('div');
                  row.style.display = 'grid';
                  row.style.gridTemplateColumns = '1fr auto 1fr';
                  row.style.gap = '8px';
                  row.style.alignItems = 'center';
                  row.style.marginBottom = '10px';

                  const freeCard = document.createElement('div');
                  freeCard.style.border = freeDone ? '1px solid #58e4b6' : '1px solid #3a5b7e';
                  freeCard.style.borderRadius = '8px';
                  freeCard.style.padding = '8px';
                  freeCard.style.background = freeDone ? 'rgba(88,228,182,0.08)' : 'rgba(15,28,44,0.75)';
                  freeCard.innerHTML = `<div style="font-size:10px;font-weight:900;color:#8fd8ff;">FREE</div><div style="font-size:11px;color:#d7ecff;">${seasonTrackRewardText(tier.free)}</div>`;
                  const freeBtn = document.createElement('button');
                  freeBtn.textContent = freeDone ? 'Claimed' : (tierUnlocked ? 'Claim' : 'Locked');
                  freeBtn.style.width = '100%';
                  freeBtn.style.marginTop = '6px';
                  freeBtn.style.padding = '5px 7px';
                  freeBtn.style.border = 'none';
                  freeBtn.style.borderRadius = '6px';
                  freeBtn.style.fontWeight = '800';
                  freeBtn.style.cursor = tierUnlocked && !freeDone ? 'pointer' : 'default';
                  freeBtn.style.background = freeDone ? '#5f6f82' : (tierUnlocked ? '#5ec4ff' : '#2d425a');
                  freeBtn.style.color = '#061120';
                  freeBtn.onclick = () => {
                      if (!tierUnlocked || freeDone) return;
                      if (claimSeasonPassTrackReward(tier.tier, 'free')) {
                          document.body.removeChild(overlay);
                          openQuestBoard();
                      }
                  };
                  freeCard.appendChild(freeBtn);

                  const center = document.createElement('div');
                  center.style.display = 'flex';
                  center.style.flexDirection = 'column';
                  center.style.alignItems = 'center';
                  center.style.justifyContent = 'center';
                  center.innerHTML = `
                      <div style="width:36px;height:36px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:900;border:2px solid ${tierUnlocked ? '#ffb15a' : '#415a73'};color:${tierUnlocked ? '#ffcf99' : '#7f97b2'};background:${tierUnlocked ? 'rgba(255,177,90,0.15)' : 'rgba(26,39,56,0.6)'};">${tier.tier}</div>
                      <div style="font-size:10px;color:#95b8d4;margin-top:3px;max-width:72px;text-align:center;">${tier.title}</div>
                  `;

                  const premiumCard = document.createElement('div');
                  premiumCard.style.border = premiumDone ? '1px solid #58e4b6' : '1px solid #8e6b2e';
                  premiumCard.style.borderRadius = '8px';
                  premiumCard.style.padding = '8px';
                  premiumCard.style.background = premiumDone ? 'rgba(88,228,182,0.08)' : 'rgba(39,23,12,0.72)';
                  premiumCard.innerHTML = `<div style="font-size:10px;font-weight:900;color:#ffd39a;">PREMIUM</div><div style="font-size:11px;color:#ffe7c9;">${seasonTrackRewardText(tier.premium)}</div>`;
                  const premiumBtn = document.createElement('button');
                  premiumBtn.textContent = premiumDone ? 'Claimed' : (!pass.premiumUnlocked ? 'Unlock Track' : (tierUnlocked ? 'Claim' : 'Locked'));
                  premiumBtn.style.width = '100%';
                  premiumBtn.style.marginTop = '6px';
                  premiumBtn.style.padding = '5px 7px';
                  premiumBtn.style.border = 'none';
                  premiumBtn.style.borderRadius = '6px';
                  premiumBtn.style.fontWeight = '800';
                  premiumBtn.style.cursor = (pass.premiumUnlocked && tierUnlocked && !premiumDone) ? 'pointer' : 'default';
                  premiumBtn.style.background = premiumDone ? '#5f6f82' : ((pass.premiumUnlocked && tierUnlocked) ? '#ffb15a' : '#5a4a33');
                  premiumBtn.style.color = '#061120';
                  premiumBtn.onclick = () => {
                      if (!pass.premiumUnlocked || !tierUnlocked || premiumDone) return;
                      if (claimSeasonPassTrackReward(tier.tier, 'premium')) {
                          document.body.removeChild(overlay);
                          openQuestBoard();
                      }
                  };
                  premiumCard.appendChild(premiumBtn);

                  row.appendChild(freeCard);
                  row.appendChild(center);
                  row.appendChild(premiumCard);
                  ladderList.appendChild(row);
              }
              ladderBox.appendChild(ladderList);

              wrapper.appendChild(questBox);
              wrapper.appendChild(ladderBox);
              return wrapper;
          }

          const views = {
              core: createCoreView,
              limited: createLimitedView,
              season: createSeasonView
          };

          function setActiveTab(tabId) {
              content.innerHTML = '';
              content.appendChild(views[tabId]());
              for (const btn of tabRow.querySelectorAll('button')) {
                  const active = btn.dataset.tab === tabId;
                  btn.style.background = active ? '#5ec4ff' : '#1a2a40';
                  btn.style.color = active ? '#00111f' : '#bde8ff';
                  btn.style.borderColor = active ? '#5ec4ff' : '#2f4f70';
              }
          }

          function makeTab(id, label) {
              const btn = document.createElement('button');
              btn.dataset.tab = id;
              btn.textContent = label;
              btn.style.padding = '8px 12px';
              btn.style.borderRadius = '8px';
              btn.style.border = '1px solid #2f4f70';
              btn.style.cursor = 'pointer';
              btn.style.fontWeight = '800';
              btn.onclick = () => setActiveTab(id);
              tabRow.appendChild(btn);
          }

          makeTab('core', 'Daily + Weekly + Starter');
          makeTab('limited', 'Limited-Time Quests');
          if (ENABLE_SEASON_QUESTS) makeTab('season', 'Season Quests');
          setActiveTab('core');

          panel.appendChild(top);
          panel.appendChild(tabRow);
          panel.appendChild(content);
          overlay.appendChild(panel);
          document.body.appendChild(overlay);
      }

      function resetEventQuestsForAll() {
      // Reset all player quest progress and drops
      playerData.event = {
          quests: {},
          questsCompleted: 0,
          milestonesClaimed: [],
          drops: [],
          startDropClaimed: false
      };
      playerData.eventTappers = { common: 0, rare: 0, epic: 0, mythic: 0 };
      
      // Rebuild quest structure
      for (const q of buildEventQuests()) {
          playerData.event.quests[q.id] = { id: q.id, kind: q.kind, stage: q.stage, progress: 0, target: q.target, title: q.title, desc: q.desc, completed: false };
      }
      
      playerData.event.questSchemaVersion = EVENT_QUEST_SCHEMA_VERSION;
      saveProgress();
      updateEventBadge();
  }

  function resetEventQuests() {
          playerData.event = playerData.event || {};
          playerData.event.quests = {};
          playerData.event.questsCompleted = 0;
          playerData.event.milestonesClaimed = [];
          playerData.event.questSchemaVersion = EVENT_QUEST_SCHEMA_VERSION;
          for (const q of buildEventQuests()) {
              playerData.event.quests[q.id] = { id: q.id, kind: q.kind, stage: q.stage, progress: 0, target: q.target, title: q.title, desc: q.desc, completed: false };
          }
          saveProgress();
          updateEventBadge();
      }

