    function getBrawlerPortraitIcon(brawlerId) {
        return brawlerPortraitIcons[brawlerId] || '⭐';
    }

    const brawlerTraitData = {
        echo: ['Can Walk Over Water'],
        copyphase: ['Can Walk Over Water'],
        goonbob: ['Can Walk Over Water'],
        unopcoloco: ['Can Walk Over Water During Super Leap', 'Passive Super Charge (Moving)'],
        dashaholic: ['Can Walk Over Water During Super/Gadget'],
        tempo_maker: ['Can Walk Over Water During Super Jump'],
        bowlin_rida: ['Skips Water At Max Speed'],
        scuba_diver: ['Can Walk Over Water'],
        forest: ['Parrot Can Fly Over Water'],
        hyperorigin: ['Passive Super Charge (Moving)', 'Charges Hyper By Taking Damage']
    };

    function getBrawlerTraits(id) {
        return brawlerTraitData[id] || [];
    }

    function ensureBeastState(entity) {
        if (!entity) return;
        if (typeof entity.beastModeActive !== 'boolean') entity.beastModeActive = false;
        if (typeof entity.beastTransformUntil !== 'number') entity.beastTransformUntil = 0;
        if (typeof entity.beastModeUntil !== 'number') entity.beastModeUntil = 0;
        if (typeof entity.beastBaseMaxHp !== 'number') entity.beastBaseMaxHp = entity.maxHp || 0;
        if (typeof entity.beastMoveMult !== 'number') entity.beastMoveMult = 1.0;
        if (typeof entity.beastAttackFlip !== 'number') entity.beastAttackFlip = 0;
        if (typeof entity.beastTransformed !== 'boolean') entity.beastTransformed = false;
    }

    function startBeastTransform(entity, now, isHyper) {
        if (!entity) return;
        ensureBeastState(entity);
        entity.beastBaseMaxHp = (typeof entity.beastBaseMaxHp === 'number' && entity.beastBaseMaxHp > 0) ? entity.beastBaseMaxHp : (entity.maxHp || 0);
        entity.beastTransformUntil = now + 850;
        entity.beastModeUntil = now + (isHyper ? 10000 : 8000);
        entity.beastModeActive = false;
        entity.beastTransformed = false;
        entity.beastMoveMult = 1.0;
        entity.beastHyper = !!isHyper;
    }

    function updateBeastState(entity, now, isHyper) {
        if (!entity || !entity.beastModeUntil) return;
        ensureBeastState(entity);

        if (!entity.beastModeActive && entity.beastTransformUntil && now >= entity.beastTransformUntil && now < entity.beastModeUntil) {
            entity.beastModeActive = true;
            if (!entity.beastTransformed) {
                const baseMaxHp = entity.beastBaseMaxHp || entity.maxHp || 0;
                const hpBoost = Math.round(baseMaxHp * 0.20);
                entity.maxHp = Math.round(baseMaxHp * 1.20);
                entity.hp = Math.min(entity.maxHp, entity.hp + hpBoost);
                entity.beastTransformed = true;
            }
            entity.beastMoveMult = entity.beastHyper ? 1.40 : 1.30;
        }

        if (entity.beastModeActive && now >= entity.beastModeUntil) {
            entity.beastModeActive = false;
            entity.beastTransformUntil = 0;
            entity.beastModeUntil = 0;
            entity.beastMoveMult = 1.0;
            entity.beastHyper = false;
            if (entity.beastBaseMaxHp) {
                entity.maxHp = entity.beastBaseMaxHp;
                entity.hp = Math.min(entity.hp, entity.maxHp);
            }
            entity.eventEmpoweredBeast = false;
            entity.forceBeastCombat = false;
        }
    }

    function ensureCrystalState(entity) {
        if (!entity) return;
        if (typeof entity.bouncyBallsCrystalUntil !== 'number') entity.bouncyBallsCrystalUntil = 0;
        if (typeof entity.bouncyBallsCrystalActive !== 'boolean') entity.bouncyBallsCrystalActive = false;
        if (typeof entity.bouncyBallsCrystalHyper !== 'boolean') entity.bouncyBallsCrystalHyper = false;
        if (typeof entity.bouncyBallsCrystalAutoChargeUntil !== 'number') entity.bouncyBallsCrystalAutoChargeUntil = 0;
    }

    function triggerBouncyBallsCrystalMode(entity, durationMs = 10000, isHyperForm = true) {
        if (!entity || entity.hp <= 0) return;
        const now = performance.now();
        ensureCrystalState(entity);
        entity.bouncyBallsCrystalUntil = now + durationMs;
        entity.bouncyBallsCrystalStartedAt = now;
        entity.bouncyBallsCrystalActive = true;
        entity.bouncyBallsCrystalHyper = !!isHyperForm;
        entity.bouncyBallsCrystalAutoChargeUntil = now + durationMs;
        if (entity === player) {
            superCharge = 100;
        } else {
            entity.superCharge = 100;
        }
    }

    function updateCrystalState(entity, now) {
        if (!entity) return;
        ensureCrystalState(entity);
        if (entity.bouncyBallsCrystalActive && now >= entity.bouncyBallsCrystalUntil) {
            entity.bouncyBallsCrystalActive = false;
            entity.bouncyBallsCrystalHyper = false;
            entity.bouncyBallsCrystalAutoChargeUntil = 0;
            entity.bouncyBallsCrystalUntil = 0;
            entity.bouncyBallsCrystalStartedAt = 0;
        }
    }

