  function resetTutorialProgress() {
      tutorialProgress = { move: false, attack: false, gadget: false, super: false, hyper: false };
      tutorialTravelDistance = 0;
      tutorialLastShotSeen = 0;
      tutorialLastPlayerPos = { x: player.x, y: player.y };
  }

  function getTutorialCurrentStep() {
      for (const step of TUTORIAL_GUIDE_STEPS) {
          if (!tutorialProgress[step.key]) return step;
      }
      return null;
  }

  function getTutorialCompletedCount() {
      return TUTORIAL_GUIDE_STEPS.filter(step => tutorialProgress[step.key]).length;
  }

  function pickShowdownModifierForMode(mode) {
      const pool = SHOWDOWN_MODE_MODIFIER_POOLS[mode] || ['none'];
      if (!pool.length) return 'none';
      const slot = Math.floor(Date.now() / MODE_MODIFIER_ROTATE_MS);
      return pool[Math.abs(slot) % pool.length] || 'none';
  }

  function setShowdownModifier(mode) {
      activeShowdownModifier = pickShowdownModifierForMode(mode);
      activeShowdownModifierLabel = (SHOWDOWN_MODE_MODIFIER_META[activeShowdownModifier] || SHOWDOWN_MODE_MODIFIER_META.none).label;
  }

  function clearShowdownModifier() {
      activeShowdownModifier = 'none';
      activeShowdownModifierLabel = SHOWDOWN_MODE_MODIFIER_META.none.label;
  }

  function applyShowdownModifierMapRules() {
      if (activeShowdownModifier !== 'no_free_cubes') return;
      if (!Array.isArray(cubes) || cubes.length <= 10) return;
      const kept = [];
      for (const c of cubes) {
          if (Math.random() < 0.35) kept.push(c);
      }
      if (kept.length < 10) {
          cubes.sort(() => Math.random() - 0.5);
          while (kept.length < 10 && cubes.length > 0) kept.push(cubes.pop());
      }
      cubes.length = 0;
      cubes.push(...kept);
  }

  function getModeStormDurationSeconds() {
      return activeShowdownModifier === 'heavy_storm' ? 90 : 120;
  }

  function getModeStormDamageMultiplier() {
      return activeShowdownModifier === 'heavy_storm' ? 1.35 : 1.0;
  }

  function getModeSuperGainMultiplier() {
      return activeShowdownModifier === 'power_surge' ? 1.2 : 1.0;
  }

