  const baseSpread = 0.45; // shared base spread
  const coneRange = 140; // bullets removed after this distance from player
  const cubes = [];
  function rectCircleCollides(rx,ry,rw,rh, cx,cy,cr){
    const closestX = Math.max(rx, Math.min(cx, rx+rw));
    const closestY = Math.max(ry, Math.min(cy, ry+rh));
    const dx = cx - closestX; const dy = cy - closestY;
    return (dx*dx + dy*dy) < (cr*cr);
  }

  function intersectRayAABB(startX, startY, dx, dy, rx, ry, rw, rh) {
      let tMin = 0;
      let tMax = 1;
      
      if (Math.abs(dx) < 1e-6) {
          if (startX < rx || startX > rx + rw) return null;
      } else {
          let t1 = (rx - startX) / dx;
          let t2 = (rx + rw - startX) / dx;
          let tNear = Math.min(t1, t2);
          let tFar = Math.max(t1, t2);
          tMin = Math.max(tMin, tNear);
          tMax = Math.min(tMax, tFar);
      }
      
      if (Math.abs(dy) < 1e-6) {
          if (startY < ry || startY > ry + rh) return null;
      } else {
          let t1 = (ry - startY) / dy;
          let t2 = (ry + rh - startY) / dy;
          let tNear = Math.min(t1, t2);
          let tFar = Math.max(t1, t2);
          tMin = Math.max(tMin, tNear);
          tMax = Math.min(tMax, tFar);
      }
      
      if (tMin <= tMax && tMin >= 0 && tMin <= 1) {
          return tMin;
      }
      return null;
  }

  function lineCircleIntersection(x1, y1, x2, y2, cx, cy, cr) {
      const dx = x2 - x1;
      const dy = y2 - y1;
      const lenSq = dx * dx + dy * dy;
      if (lenSq === 0) {
          return Math.hypot(cx - x1, cy - y1) <= cr;
      }
      let t = ((cx - x1) * dx + (cy - y1) * dy) / lenSq;
      t = Math.max(0, Math.min(1, t));
      const projX = x1 + t * dx;
      const projY = y1 + t * dy;
      const distSq = (cx - projX) * (cx - projX) + (cy - projY) * (cy - projY);
      return distSq <= cr * cr;
  }


    function getRotatingShowdownMapIndex() {
        return Math.floor(Date.now() / SHOWDOWN_MAP_ROTATION_MS) % SHOWDOWN_MAP_THEMES.length;
    }

    function getRotatingConstructionMapIndex() {
        return Math.floor(Date.now() / SHOWDOWN_MAP_ROTATION_MS) % 2;
    }

    function getActiveShowdownMapIndex() {
        if (typeof currentMapOverride === 'number' && Number.isFinite(currentMapOverride)) {
            const idx = Math.floor(currentMapOverride);
            const len = SHOWDOWN_MAP_THEMES.length;
            return ((idx % len) + len) % len;
        }
        if (playing && !isTraining && !isDuels && !isBossFight && !isSoloTrial) {
            return showdownMapIndex;
        }
        return getRotatingShowdownMapIndex();
    }

    function getActiveShowdownTheme() {
        return SHOWDOWN_MAP_THEMES[getActiveShowdownMapIndex()] || SHOWDOWN_MAP_THEMES[0];
    }

    function getActiveConstructionMapIndex() {
        const idx = Number.isFinite(constructionMapIndex) ? constructionMapIndex : 0;
        return ((Math.floor(idx) % 2) + 2) % 2;
    }

    function getConstructionMapName() {
        return getActiveConstructionMapIndex() === 0 ? 'S-Curve Depot' : 'Twin Arcs Yard';
    }

    function isEntityInsideWater(entity) {
        if (!entity) return false;
        const r = entity.radius || 14;
        return waterZones.some((zone) => rectCircleCollides(zone.x, zone.y, zone.w, zone.h, entity.x, entity.y, r));
    }

    function isCircleInWaterAt(x, y, radius = 14) {
        return waterZones.some((zone) => rectCircleCollides(zone.x, zone.y, zone.w, zone.h, x, y, radius));
    }

    function canEntityTraverseWater(entity) {
        if (!entity) return false;
        const brawlerId = entity.id === player.id ? selectedBrawler : (entity.brawler || 'outlit');
        if (brawlerId === 'echo' || brawlerId === 'copyphase' || brawlerId === 'goonbob') return true;
        if (brawlerId === 'unopcoloco') return !!entity.isJumping;
        if (brawlerId === 'dashaholic') return !!entity.isDashing;
        if (brawlerId === 'tempo_maker') return !!entity.isJumping;
        if (brawlerId === 'bowlin_rida') return !!entity.isFlying;
        if (brawlerId === 'scuba_diver') return true;
        if (brawlerId === 'parrot' || brawlerId === 'egg') return true;
        return false;
    }

    function canMoveToPosition(entity, x, y) {
        if (!entity) return true;
        if (canEntityTraverseWater(entity)) return true;
        return !isCircleInWaterAt(x, y, entity.radius || 14);
    }

    function isCircleBlockedByTerrain(entity, x, y, radius = 14) {
        if (cubes.some((c) => rectCircleCollides(c.x, c.y, c.w, c.h, x, y, radius))) return true;
        for (const w of destructibleWalls) {
            if (!w || w.isPlatform) continue;
            if (entity && w.ownerId === entity.id) continue;
            if (rectCircleCollides(w.x, w.y, w.w, w.h, x, y, radius)) return true;
        }
        return false;
    }

    function canBotMoveToPosition(entity, x, y) {
        if (!entity) return false;
        if (!canMoveToPosition(entity, x, y)) return false;
        return !isCircleBlockedByTerrain(entity, x, y, entity.radius || 14);
    }

    function getBotSteeredStep(entity, dx, dy, speed, dt) {
        const dist = Math.hypot(dx, dy) || 1;
        const baseDirX = dx / dist;
        const baseDirY = dy / dist;
        const stride = speed * dt;
        const angles = [0, 0.34, -0.34, 0.65, -0.65, 1.05, -1.05, 1.45, -1.45];
        for (const ang of angles) {
            const cosA = Math.cos(ang);
            const sinA = Math.sin(ang);
            const dirX = baseDirX * cosA - baseDirY * sinA;
            const dirY = baseDirX * sinA + baseDirY * cosA;
            const nx = entity.x + dirX * stride;
            const ny = entity.y + dirY * stride;
            if (!canBotMoveToPosition(entity, nx, ny)) continue;
            return { moved: true, x: nx, y: ny, vx: dirX * speed, vy: dirY * speed };
        }

        // Axis slide fallback for tight corridors.
        const nx = entity.x + baseDirX * stride;
        if (canBotMoveToPosition(entity, nx, entity.y)) {
            return { moved: true, x: nx, y: entity.y, vx: baseDirX * speed, vy: 0 };
        }
        const ny = entity.y + baseDirY * stride;
        if (canBotMoveToPosition(entity, entity.x, ny)) {
            return { moved: true, x: entity.x, y: ny, vx: 0, vy: baseDirY * speed };
        }
        return { moved: false, x: entity.x, y: entity.y, vx: 0, vy: 0 };
    }

    function canDetectThroughBush(observer, target, revealRange = 240) {
        if (!observer || !target) return true;
        if (!isEntityInsideBush(target)) return true;
        if (isEntityInsideBush(observer)) return true;
        return Math.hypot(observer.x - target.x, observer.y - target.y) <= revealRange;
    }

    function findNearestDrySpot(x, y, radius = 14) {
        const startX = clamp(x, radius, WORLD_W - radius);
        const startY = clamp(y, radius, WORLD_H - radius);
        if (!isCircleInWaterAt(startX, startY, radius)) return { x: startX, y: startY };

        for (let dist = 18; dist <= 620; dist += 18) {
            for (let a = 0; a < Math.PI * 2; a += Math.PI / 10) {
                const tx = clamp(startX + Math.cos(a) * dist, radius, WORLD_W - radius);
                const ty = clamp(startY + Math.sin(a) * dist, radius, WORLD_H - radius);
                if (!isCircleInWaterAt(tx, ty, radius)) return { x: tx, y: ty };
            }
        }
        return { x: startX, y: startY };
    }

    function ensureEntityOnDryLand(entity) {
        if (!entity || entity.hp <= 0) return;
        if (canEntityTraverseWater(entity)) return;
        if (!isEntityInsideWater(entity)) return;
        const dry = findNearestDrySpot(entity.x, entity.y, entity.radius || 14);
        entity.x = dry.x;
        entity.y = dry.y;
    }

    function isEntityInsideBush(entity) {
        if (!entity) return false;
        const r = entity.radius || 14;
        return bushZones.some((zone) => rectCircleCollides(zone.x, zone.y, zone.w, zone.h, entity.x, entity.y, r));
    }

    function getTerrainMoveMultiplier(entity) {
        if (!isEntityInsideWater(entity)) return 1.0;
        return canEntityTraverseWater(entity) ? 1.0 : 0.74;
    }

    function getShowdownSpawnPosition() {
        if (isPowerGodsMode) {
            const points = getPowerGodsSpawnPoints();
            const start = getActiveShowdownMapIndex() % points.length;
            const p = points[start];
            return findNearestDrySpot(p.x, p.y, player.radius || 16);
        }
        const candidates = [
            { x: 560, y: 560 },
            { x: WORLD_W - 560, y: 560 },
            { x: WORLD_W - 560, y: WORLD_H - 560 },
            { x: 560, y: WORLD_H - 560 },
            { x: WORLD_W * 0.5, y: 460 },
            { x: WORLD_W * 0.5, y: WORLD_H - 460 },
            { x: 460, y: WORLD_H * 0.5 },
            { x: WORLD_W - 460, y: WORLD_H * 0.5 }
        ];
        const start = getActiveShowdownMapIndex() % candidates.length;
        for (let i = 0; i < candidates.length; i++) {
            const c = candidates[(start + i) % candidates.length];
            const dry = findNearestDrySpot(c.x, c.y, player.radius || 16);
            if (!isCircleInWaterAt(dry.x, dry.y, player.radius || 16)) return dry;
        }
        return findNearestDrySpot(WORLD_W * 0.5, WORLD_H * 0.5, player.radius || 16);
    }

    function getPowerGodsSpawnPoints() {
        const margin = 440;
        return [
            { x: margin, y: margin },
            { x: WORLD_W * 0.5, y: margin * 0.85 },
            { x: WORLD_W - margin, y: margin },
            { x: WORLD_W - margin * 0.85, y: WORLD_H * 0.5 },
            { x: WORLD_W - margin, y: WORLD_H - margin },
            { x: WORLD_W * 0.5, y: WORLD_H - margin * 0.85 },
            { x: margin, y: WORLD_H - margin },
            { x: margin * 0.85, y: WORLD_H * 0.5 },
            { x: WORLD_W * 0.3, y: WORLD_H * 0.3 },
            { x: WORLD_W * 0.7, y: WORLD_H * 0.7 }
        ];
    }

    function isInsidePowerGodsSafeZone(x, y, extraRadius = 0) {
        if (!isPowerGodsMode) return false;
        const safeR = 220 + extraRadius;
        const points = getPowerGodsSpawnPoints();
        for (const p of points) {
            if (Math.hypot(x - p.x, y - p.y) <= safeR) return true;
        }
        return false;
    }

    function isObjectiveZonePlayable(x, y, radius) {
        const samples = 18;
        let wet = 0;
        let total = 0;
        for (let i = 0; i < samples; i++) {
            const a = (Math.PI * 2 * i) / samples;
            const d = radius * (0.25 + 0.75 * (i % 3) / 2);
            const sx = clamp(x + Math.cos(a) * d, radius, WORLD_W - radius);
            const sy = clamp(y + Math.sin(a) * d, radius, WORLD_H - radius);
            total++;
            if (isCircleInWaterAt(sx, sy, 10)) wet++;
        }
        total++;
        if (isCircleInWaterAt(x, y, 12)) wet++;
        return (wet / total) <= 0.25;
    }

    function chooseObjectiveZonePosition() {
        const r = BALANCE_PROFILE.objectiveMode.zoneRadius;
        const candidates = [
            { x: WORLD_W * 0.5, y: WORLD_H * 0.5 },
            { x: WORLD_W * 0.5, y: WORLD_H * 0.36 },
            { x: WORLD_W * 0.5, y: WORLD_H * 0.64 },
            { x: WORLD_W * 0.36, y: WORLD_H * 0.5 },
            { x: WORLD_W * 0.64, y: WORLD_H * 0.5 },
            { x: WORLD_W * 0.33, y: WORLD_H * 0.33 },
            { x: WORLD_W * 0.67, y: WORLD_H * 0.67 },
            { x: WORLD_W * 0.67, y: WORLD_H * 0.33 },
            { x: WORLD_W * 0.33, y: WORLD_H * 0.67 }
        ];
        const start = getActiveShowdownMapIndex() % candidates.length;
        for (let i = 0; i < candidates.length; i++) {
            const c = candidates[(start + i) % candidates.length];
            const dry = findNearestDrySpot(c.x, c.y, 16);
            if (isObjectiveZonePlayable(dry.x, dry.y, r)) {
                return { x: dry.x, y: dry.y, r };
            }
        }
        const fallback = findNearestDrySpot(WORLD_W * 0.5, WORLD_H * 0.5, 16);
        return { x: fallback.x, y: fallback.y, r };
    }

    function getConstructionOpposingTeam(team) {
        return team === 'player' ? 'enemy' : 'player';
    }

    function buildConstructionPath(start, control, end) {
        return {
            start: findNearestDrySpot(start.x, start.y, 16),
            control: findNearestDrySpot(control.x, control.y, 16),
            end: findNearestDrySpot(end.x, end.y, 16)
        };
    }

    function initConstructionModeState() {
        constructionWinnerTeam = null;
        constructionPaths.player = buildConstructionPath(
            { x: WORLD_W * 0.2, y: WORLD_H * 0.78 },
            { x: WORLD_W * 0.5, y: WORLD_H * 0.56 },
            { x: WORLD_W * 0.8, y: WORLD_H * 0.28 }
        );
        constructionPaths.enemy = buildConstructionPath(
            { x: WORLD_W * 0.8, y: WORLD_H * 0.22 },
            { x: WORLD_W * 0.5, y: WORLD_H * 0.44 },
            { x: WORLD_W * 0.2, y: WORLD_H * 0.72 }
        );
        constructionCarts.player = { progress: 0, siteTimer: 0, siteDamage: 0 };
        constructionCarts.enemy = { progress: 0, siteTimer: 0, siteDamage: 0 };
    }

    function getPointOnConstructionPath(path, t) {
        const u = 1 - t;
        return {
            x: (u * u * path.start.x) + (2 * u * t * path.control.x) + (t * t * path.end.x),
            y: (u * u * path.start.y) + (2 * u * t * path.control.y) + (t * t * path.end.y)
        };
    }

    function getConstructionCartPosition(team) {
        const path = constructionPaths[team];
        const cart = constructionCarts[team];
        if (!path || !cart) return null;
        const t = clamp((cart.progress || 0) / 100, 0, 1);
        return getPointOnConstructionPath(path, t);
    }

    function getConstructionSpawnPoint(team, slot = 0, teamSize = 3) {
        const path = constructionPaths[team] || constructionPaths.player;
        const base = path ? path.start : { x: WORLD_W * 0.5, y: WORLD_H * 0.5 };
        const spread = Math.max(1, teamSize - 1);
        const offset = (slot - spread * 0.5) * 55;
        const px = clamp(base.x + offset, 60, WORLD_W - 60);
        const py = clamp(base.y + ((team === 'player') ? 80 : -80), 60, WORLD_H - 60);
        return findNearestDrySpot(px, py, 16);
    }

    function isInConstructionCartZone(entity, team) {
        if (!entity || entity.hp <= 0) return false;
        const cartPos = getConstructionCartPosition(team);
        if (!cartPos) return false;
        return Math.hypot(entity.x - cartPos.x, entity.y - cartPos.y) <= CONSTRUCTION_CART_ZONE_RADIUS;
    }

    function registerConstructionCartDamage(ownerId, damageAmount) {
        if (!isConstructionMode || !playing || gameOver || damageAmount <= 0) return;
        const owner = ownerId === player.id ? player : bots.find(bt => bt.id === ownerId);
        if (!owner || owner.hp <= 0) return;
        const ownerTeam = owner.team === 'player' ? 'player' : 'enemy';
        const enemyTeam = getConstructionOpposingTeam(ownerTeam);
        const enemyCart = constructionCarts[enemyTeam];
        if (!enemyCart || enemyCart.progress < 100) return;
        if (!isInConstructionCartZone(owner, enemyTeam)) return;

        enemyCart.siteDamage += damageAmount;
        while (enemyCart.siteDamage >= CONSTRUCTION_PUSHBACK_DAMAGE_REQUIREMENT) {
            enemyCart.siteDamage -= CONSTRUCTION_PUSHBACK_DAMAGE_REQUIREMENT;
            enemyCart.progress = Math.max(0, enemyCart.progress - CONSTRUCTION_PUSHBACK_PERCENT);
            enemyCart.siteTimer = 0;
            const cartPos = getConstructionCartPosition(enemyTeam);
            if (cartPos) {
                spawnFloatingText(cartPos.x, cartPos.y - 34, 'Cart pushed back -10%', '#ffd166');
            }
        }
    }

    function initDamageFillerModeState(teamSize = 2, goalOverride = 0) {
        if (teamSize === SPLITTER_POWERED_TEAM_SIZE) damageFillerTeamSize = SPLITTER_POWERED_TEAM_SIZE;
        else damageFillerTeamSize = teamSize === 3 ? 3 : 2;
        damageFillerGoal = goalOverride > 0
            ? goalOverride
            : (damageFillerTeamSize === 3 ? 150000 : 100000);
        damageFillerWinnerTeam = null;
        damageFillerScores.player = 0;
        damageFillerScores.enemy = 0;
        damageFillerNextCubeSpawn = performance.now() + 2000 + Math.random() * 1400;
    }

    function initSplitterPoweredModeState() {
        splitterPoweredRound = 1;
        splitterPoweredRound2BoostTeam = null;
        splitterPoweredObjectiveDamage.player = 0;
        splitterPoweredObjectiveDamage.enemy = 0;
        splitterPoweredObjectiveTotalDamage = 0;
        splitterPoweredObjectiveDummyId = null;
        damageFillerScores.player = 0;
        damageFillerScores.enemy = 0;
        damageFillerGoal = SPLITTER_POWERED_ROUND2_GOAL;
    }

    function spawnSplitterPoweredObjectiveDummy() {
        if (!isSplitterPoweredMode) return;
        for (let i = bots.length - 1; i >= 0; i--) {
            if (bots[i]?.isSplitterObjectiveDummy) bots.splice(i, 1);
        }
        const hp = 50000000;
        const dummy = {
            id: nextId++,
            x: WORLD_W * 0.5,
            y: WORLD_H * 0.5,
            z: 0,
            vx: 0,
            vy: 0,
            hp,
            maxHp: hp,
            powerCubes: 0,
            isDead: false,
            shield: 0,
            shieldMax: 0,
            shieldDecayTimer: 0,
            reloadBuffUntil: 0,
            radius: 56,
            speed: 0,
            slowUntil: 0,
            brawler: 'outlit',
            level: 11,
            gadgetUnlocked: false,
            starPowerUnlocked: false,
            hyperchargeUnlocked: false,
            lastTargetId: null,
            targetLockUntil: 0,
            lastShot: 0,
            superCharge: 0,
            hyperChargeCharge: 0,
            isHypercharged: false,
            hyperchargeUntil: 0,
            gadgetArmed: false,
            gadgetCooldownUntil: 0,
            selectedStar: 'none',
            selectedGadget: 'g1',
            unopcolocoCycle: 0,
            minigunAmmo: 0,
            minigunPierceShots: 0,
            ridaSpeedMult: 1.0,
            ridaHitCooldowns: {},
            isFlying: false,
            moneyAndTaxMode: 'money',
            team: 'objective',
            isDummy: true,
            isSplitterObjectiveDummy: true,
            respawnTimer: 0
        };
        bots.push(dummy);
        splitterPoweredObjectiveDummyId = dummy.id;
    }

    function getSplitterMainSplitConfig(isHyper, isBotControlled = false) {
        if (!isSplitterPoweredMode) {
            return {
                splitPlan: isHyper ? [3, 4, 2, 2] : [3, 4],
                generationCaps: null,
                childCap: SPLITTER_MAIN_CHILD_CAP,
                mainDamageMult: 1,
                childDamageMult: 0.58,
                hyperDamageMult: 1,
                hyperChildMult: 1,
            };
        }
        const inRoundTwo = splitterPoweredRound >= 2;
        const mainDamageBase = inRoundTwo ? 0.9 : SPLITTER_POWERED_BASE_MAIN_DAMAGE_MULT;
        const childDamageBase = inRoundTwo ? 0.56 : SPLITTER_POWERED_BASE_CHILD_DAMAGE_MULT;
        const splitPlan = isBotControlled ? SPLITTER_POWERED_BOT_MAIN_SPLIT_PLAN : SPLITTER_POWERED_MAIN_SPLIT_PLAN;
        const generationCaps = isBotControlled ? SPLITTER_POWERED_BOT_MAIN_GEN_CAPS : SPLITTER_POWERED_MAIN_GEN_CAPS;
        const childCap = isBotControlled ? SPLITTER_POWERED_BOT_MAIN_CHILD_CAP : SPLITTER_POWERED_MAIN_CHILD_CAP;
        return {
            splitPlan: splitPlan.slice(),
            generationCaps: generationCaps.slice(),
            childCap,
            mainDamageMult: mainDamageBase,
            childDamageMult: childDamageBase,
            hyperDamageMult: isHyper ? SPLITTER_POWERED_HYPER_MAIN_DAMAGE_MULT : 1,
            hyperChildMult: isHyper ? SPLITTER_POWERED_HYPER_CHILD_DAMAGE_MULT : 1,
        };
    }

    function getDamageFillerSpawnPoint(team, slot = 0, teamSize = 2) {
        const spread = Math.max(1, teamSize - 1);
        const laneOffset = (slot - spread * 0.5) * 24;
        const xRange = team === 'player' ? [0.12, 0.3] : [0.7, 0.88];
        const yBands = [0.2, 0.34, 0.5, 0.66, 0.8];
        const entities = [player, ...bots];
        let bestSpot = null;
        let bestScore = -Infinity;

        for (let i = 0; i < 24; i++) {
            const yBand = yBands[Math.floor(Math.random() * yBands.length)];
            const rawX = WORLD_W * (xRange[0] + Math.random() * (xRange[1] - xRange[0]));
            const rawY = WORLD_H * yBand + (Math.random() * 140 - 70) + laneOffset;
            const spot = findNearestDrySpot(clamp(rawX, 60, WORLD_W - 60), clamp(rawY, 60, WORLD_H - 60), 16);

            let nearestEnemy = Infinity;
            let closeEnemyCount = 0;
            for (const e of entities) {
                if (!e || e.hp <= 0) continue;
                const entTeam = e.id === player.id ? 'player' : (e.team === 'player' ? 'player' : 'enemy');
                if (entTeam === team) continue;
                const d = Math.hypot(e.x - spot.x, e.y - spot.y);
                if (d < nearestEnemy) nearestEnemy = d;
                if (d < 420) closeEnemyCount += 1;
            }

            const score = nearestEnemy - closeEnemyCount * 220 + Math.random() * 8;
            if (score > bestScore) {
                bestScore = score;
                bestSpot = spot;
            }
            if (nearestEnemy > 520 && closeEnemyCount === 0) return spot;
        }

        if (bestSpot) return bestSpot;
        const fallbackX = team === 'player' ? WORLD_W * 0.2 : WORLD_W * 0.8;
        return findNearestDrySpot(clamp(fallbackX, 60, WORLD_W - 60), WORLD_H * 0.5, 16);
    }

    function getBrickVaultSpawnPoint(team, slot = 0, teamSize = BRICK_VAULT_TEAM_SIZE) {
        const spread = Math.max(1, teamSize - 1);
        const laneNorm = spread > 0 ? ((slot / spread) - 0.5) : 0;
        const baseY = team === 'player' ? WORLD_H * 0.84 : WORLD_H * 0.16;
        const baseX = WORLD_W * 0.5 + laneNorm * 520;
        const clampedX = clamp(baseX, 90, WORLD_W - 90);
        return findNearestDrySpot(clampedX, clamp(baseY, 90, WORLD_H - 90), 16);
    }

    function getArenaForgeSpawnPoint(team, slot = 0, teamSize = ARENA_FORGE_TEAM_SIZE) {
        const spread = Math.max(1, teamSize - 1);
        const laneNorm = spread > 0 ? ((slot / spread) - 0.5) : 0;
        const baseY = team === 'player' ? WORLD_H * 0.86 : WORLD_H * 0.14;
        const baseX = WORLD_W * 0.5 + laneNorm * 420;
        const clampedX = clamp(baseX, 90, WORLD_W - 90);
        return findNearestDrySpot(clampedX, clamp(baseY, 90, WORLD_H - 90), 16);
    }

    function registerDamageFillerDamage(ownerId, targetId, damageAmount) {
        if (!isDamageFillerMode || !playing || gameOver || damageAmount <= 0) return;
        const owner = ownerId === player.id ? player : bots.find(bt => bt.id === ownerId);
        const target = targetId === player.id ? player : bots.find(bt => bt.id === targetId);
        if (!owner || !target) return;
        const ownerTeam = owner.id === player.id ? 'player' : (owner.team === 'player' ? 'player' : 'enemy');
        if (owner.id === player.id && isSplitterPoweredMode) {
            addEventQuestProgress('splitter_ltm_damage', Math.round(damageAmount));
        }

        if (isSplitterPoweredMode && target.isSplitterObjectiveDummy) {
            target.hp = target.maxHp;
            target.shield = 0;
            if (splitterPoweredRound !== 1) return;
            splitterPoweredObjectiveDamage[ownerTeam] = (splitterPoweredObjectiveDamage[ownerTeam] || 0) + damageAmount;
            splitterPoweredObjectiveTotalDamage = Math.min(
                SPLITTER_POWERED_ROUND1_DUMMY_GOAL,
                splitterPoweredObjectiveTotalDamage + damageAmount
            );
            if (splitterPoweredObjectiveTotalDamage < SPLITTER_POWERED_ROUND1_DUMMY_GOAL) return;

            splitterPoweredRound = 2;
            damageFillerGoal = SPLITTER_POWERED_ROUND2_GOAL;
            damageFillerScores.player = 0;
            damageFillerScores.enemy = 0;
            splitterPoweredRound2BoostTeam = null;
            if ((splitterPoweredObjectiveDamage.player || 0) > (splitterPoweredObjectiveDamage.enemy || 0)) {
                splitterPoweredRound2BoostTeam = 'player';
            } else if ((splitterPoweredObjectiveDamage.enemy || 0) > (splitterPoweredObjectiveDamage.player || 0)) {
                splitterPoweredRound2BoostTeam = 'enemy';
            }
            if (splitterPoweredRound2BoostTeam) {
                damageFillerScores[splitterPoweredRound2BoostTeam] = SPLITTER_POWERED_ROUND2_START_BOOST;
                const centerY = WORLD_H * 0.5 - 110;
                spawnFloatingText(WORLD_W * 0.5, centerY, `${splitterPoweredRound2BoostTeam.toUpperCase()} +1,000,000 ROUND 2 BOOST`, '#ffd166');
            } else {
                spawnFloatingText(WORLD_W * 0.5, WORLD_H * 0.5 - 110, 'ROUND 2 START - TIE ON DUMMY DAMAGE', '#9ee6ff');
            }
            return;
        }

        if (isSplitterPoweredMode && splitterPoweredRound === 1) {
            return;
        }

        const targetTeam = target.id === player.id ? 'player' : (target.team === 'player' ? 'player' : 'enemy');
        if (ownerTeam === targetTeam) return;

        const scoreDamage = (isSplitterPoweredMode && splitterPoweredRound >= 2)
            ? damageAmount * SPLITTER_POWERED_ROUND2_SCORE_MULT
            : damageAmount;
        damageFillerScores[ownerTeam] = (damageFillerScores[ownerTeam] || 0) + scoreDamage;
        if (damageFillerScores[ownerTeam] < damageFillerGoal) return;
        if (gameOver) return;

        damageFillerWinnerTeam = ownerTeam;
        objectiveWon = ownerTeam === 'player';
        if (ownerTeam === 'player') {
            for (const b of bots) {
                if ((b.team || 'enemy') !== 'player') b.hp = 0;
            }
        } else {
            player.hp = 0;
            for (const b of bots) {
                if ((b.team || 'enemy') === 'player') b.hp = 0;
            }
        }
        gameOver = true;
    }

    function trySpawnDamageFillerCube(now) {
        if (!isDamageFillerMode || gameOver || !playing) return;
        if (now < damageFillerNextCubeSpawn) return;
        damageFillerNextCubeSpawn = now + 2200 + Math.random() * 2600;
        if (powerups.length >= 12) return;

        for (let tries = 0; tries < 70; tries++) {
            const x = 80 + Math.random() * (WORLD_W - 160);
            const y = 80 + Math.random() * (WORLD_H - 160);
            const blockedByCube = cubes.some(c => rectCircleCollides(c.x, c.y, c.w, c.h, x, y, 16));
            const blockedByWall = destructibleWalls.some(w => rectCircleCollides(w.x, w.y, w.w, w.h, x, y, 16));
            const blockedByWater = isCircleInWaterAt(x, y, 14);
            if (blockedByCube || blockedByWall || blockedByWater) continue;
            powerups.push({ x, y });
            return;
        }
    }

    function initMirrorModeState() {
        const pool = getBotBrawlerPool({ exclude: ['parrot', 'egg'] });
        mirrorModeBrawler = pool[Math.floor(Math.random() * pool.length)] || 'outlit';
        mirrorKills.player = 0;
        mirrorKills.enemy = 0;
        mirrorWinnerTeam = null;
    }

    function getMirrorSpawnPoint(team, slot = 0, teamSize = MIRROR_TEAM_SIZE) {
        const spread = Math.max(1, teamSize - 1);
        const laneOffset = (slot - spread * 0.5) * 22;
        const xRange = team === 'player' ? [0.1, 0.28] : [0.72, 0.9];
        const yBands = [0.16, 0.3, 0.5, 0.7, 0.84];
        const entities = [player, ...bots];
        let bestSpot = null;
        let bestScore = -Infinity;

        for (let i = 0; i < 22; i++) {
            const yBand = yBands[Math.floor(Math.random() * yBands.length)];
            const rawX = WORLD_W * (xRange[0] + Math.random() * (xRange[1] - xRange[0]));
            const rawY = WORLD_H * yBand + (Math.random() * 120 - 60) + laneOffset;
            const spot = findNearestDrySpot(clamp(rawX, 60, WORLD_W - 60), clamp(rawY, 60, WORLD_H - 60), 16);
            let nearestEnemy = Infinity;
            let closeEnemyCount = 0;

            for (const e of entities) {
                if (!e || e.hp <= 0) continue;
                const entTeam = e.id === player.id ? 'player' : (e.team === 'player' ? 'player' : 'enemy');
                if (entTeam === team) continue;
                const d = Math.hypot(e.x - spot.x, e.y - spot.y);
                if (d < nearestEnemy) nearestEnemy = d;
                if (d < 420) closeEnemyCount += 1;
            }

            const score = nearestEnemy - closeEnemyCount * 220 + Math.random() * 6;
            if (score > bestScore) {
                bestScore = score;
                bestSpot = spot;
            }
            if (nearestEnemy > 500 && closeEnemyCount === 0) return spot;
        }

        if (bestSpot) return bestSpot;
        const fallbackX = team === 'player' ? WORLD_W * 0.2 : WORLD_W * 0.8;
        return findNearestDrySpot(clamp(fallbackX, 60, WORLD_W - 60), WORLD_H * 0.5, 16);
    }

    function registerMirrorKill(ownerId, victimId) {
        if (!isMirrorMode || !playing || gameOver) return;
        const victim = victimId === player.id ? player : bots.find(bt => bt.id === victimId);
        if (!victim) return;
        const victimTeam = victim.id === player.id ? 'player' : (victim.team === 'player' ? 'player' : 'enemy');
        const fallbackOwnerId = victim.lastDamagerId;
        let owner = ownerId === player.id ? player : bots.find(bt => bt.id === ownerId);
        if (!owner && fallbackOwnerId != null) {
            owner = fallbackOwnerId === player.id ? player : bots.find(bt => bt.id === fallbackOwnerId);
        }
        if (!owner) {
            owner = victimTeam === 'player'
                ? (bots.find(bt => (bt.team || 'enemy') !== 'player') || null)
                : player;
        }
        if (!owner) return;
        const ownerTeam = owner.id === player.id ? 'player' : (owner.team === 'player' ? 'player' : 'enemy');
        if (ownerTeam === victimTeam) return;
        mirrorKills[ownerTeam] = (mirrorKills[ownerTeam] || 0) + 1;
        if (mirrorKills[ownerTeam] < MIRROR_KILL_GOAL) return;

        mirrorWinnerTeam = ownerTeam;
        objectiveWon = ownerTeam === 'player';
        gameOver = true;
        if (ownerTeam === 'player') {
            for (const b of bots) if ((b.team || 'enemy') !== 'player') b.hp = 0;
        } else {
            player.hp = 0;
            for (const b of bots) if ((b.team || 'enemy') === 'player') b.hp = 0;
        }
    }

    function closeKnockDonateDonationUI() {
        if (knockDonateDonationUI && knockDonateDonationUI.isConnected) {
            knockDonateDonationUI.remove();
        }
        knockDonateDonationUI = null;
    }

    function getTeamLivingEntities(team) {
        const list = [];
        if (team === 'player' && player.hp > 0) list.push(player);
        for (const b of bots) {
            if (!b || b.hp <= 0 || b.isDummy || b.isPet) continue;
            if ((b.team || 'enemy') === team) list.push(b);
        }
        return list;
    }

    function initKnockDonateModeState() {
        knockDonateWins = { player: 0, enemy: 0 };
        knockDonateRound = 1;
        knockDonateRoundTransitionUntil = 0;
        closeKnockDonateDonationUI();
    }

    function resetEntityForRound(entity, spawn) {
        if (!entity) return;
        entity.hp = entity.maxHp;
        entity.x = spawn.x;
        entity.y = spawn.y;
        entity.z = 0;
        entity.vx = 0;
        entity.vy = 0;
        entity.isJumping = false;
        entity.isDashing = false;
        entity.isFlying = false;
        entity.slowUntil = 0;
        entity.stunUntil = 0;
        entity.poisonUntil = 0;
        entity.defenseUntil = 0;
        entity.shield = 0;
        entity.respawnTimer = 0;
        entity.isDead = false;
        entity.lastDamagerId = null;
        entity._mirrorDeathCounted = false;
        entity.malakorHellTickAt = 0;
        clearPoisonState(entity);
    }

    function resetKnockDonateRound() {
        closeKnockDonateDonationUI();
        bullets.length = 0;
        rings.length = 0;
        powerups.length = 0;
        cheeseFields.length = 0;
        stickyNotes.length = 0;
        explosions.length = 0;
        pendingClones.length = 0;
        amplifierScrewZones.length = 0;
        skeleParachutes.length = 0;
        skelePortals.length = 0;
        malakorHellZones.length = 0;
        malakorHands.length = 0;

        const teamSize = KNOCK_DONATE_TEAM_SIZE;
        resetEntityForRound(player, getDamageFillerSpawnPoint('player', 0, teamSize));
        superCharge = 0;
        hyperChargeCharge = 0;
        isHypercharged = false;
        updateSuperButton();
        updateHyperButton();
        ammo = maxAmmo;

        let playerSlot = 1;
        let enemySlot = 0;
        for (const b of bots) {
            if (!b || b.isDummy || b.isPet) continue;
            const team = (b.team === 'player') ? 'player' : 'enemy';
            const slot = team === 'player' ? playerSlot++ : enemySlot++;
            const spawn = getDamageFillerSpawnPoint(team, slot, teamSize);
            resetEntityForRound(b, spawn);
            b.superCharge = 0;
            b.hyperChargeCharge = 0;
            b.isHypercharged = false;
        }
    }

    function finishTeamModeMatch(winnerTeam) {
        closeKnockDonateDonationUI();
        objectiveWon = winnerTeam === 'player';
        if (winnerTeam === 'player') {
            for (const b of bots) {
                if ((b.team || 'enemy') !== 'player') b.hp = 0;
            }
        } else {
            player.hp = 0;
            for (const b of bots) {
                if ((b.team || 'enemy') === 'player') b.hp = 0;
            }
        }
        gameOver = true;
    }

    function resolveKnockDonateRound(winnerTeam) {
        if (!isKnockDonateMode || gameOver) return;
        knockDonateRoundTransitionUntil = performance.now() + 1400;
        knockDonateWins[winnerTeam] = (knockDonateWins[winnerTeam] || 0) + 1;
        const playerWins = knockDonateWins.player || 0;
        const enemyWins = knockDonateWins.enemy || 0;
        if (knockDonateWins[winnerTeam] >= KNOCK_DONATE_ROUNDS_TO_WIN) {
            finishTeamModeMatch(winnerTeam);
            return;
        }
        knockDonateRound = playerWins + enemyWins + 1;
        setTimeout(() => {
            if (!playing || gameOver || !isKnockDonateMode) return;
            resetKnockDonateRound();
            knockDonateRoundTransitionUntil = 0;
        }, 900);
    }

    function applyKnockDonateSuperDonation(donor, recipient) {
        if (!recipient || recipient.hp <= 0) return false;
        if ((recipient.superCharge || 0) >= 100) return false;
        recipient.superCharge = 100;
        if (recipient.id === player.id) updateSuperButton();
        spawnFloatingText(recipient.x, recipient.y - 22, 'SUPER DONATED', '#9ef6d6');
        closeKnockDonateDonationUI();
        return true;
    }

    function handleKnockDonateEntityDeath(entity) {
        if (!isKnockDonateMode || !entity || gameOver) return;
        const team = getEntityTeam(entity);
        if (!team) return;
        const aliveAllies = getTeamLivingEntities(team).filter((ally) => ally.id !== entity.id && (ally.superCharge || 0) < 100);
        if (!aliveAllies.length) {
            if (entity.id === player.id) closeKnockDonateDonationUI();
            return;
        }
        if (entity.id !== player.id) {
            const target = aliveAllies[Math.floor(Math.random() * aliveAllies.length)];
            applyKnockDonateSuperDonation(entity, target);
            return;
        }

        closeKnockDonateDonationUI();
        const overlay = document.createElement('div');
        overlay.style.position = 'fixed';
        overlay.style.left = '50%';
        overlay.style.bottom = '18px';
        overlay.style.transform = 'translateX(-50%)';
        overlay.style.zIndex = '1600';
        overlay.style.background = 'rgba(5, 14, 26, 0.92)';
        overlay.style.border = '1px solid rgba(156, 235, 255, 0.7)';
        overlay.style.borderRadius = '12px';
        overlay.style.padding = '10px';
        overlay.style.display = 'flex';
        overlay.style.gap = '8px';
        overlay.style.alignItems = 'center';
        overlay.style.fontFamily = 'sans-serif';

        const title = document.createElement('span');
        title.textContent = 'Donate full super to:';
        title.style.color = '#cfeef7';
        title.style.fontWeight = '700';
        overlay.appendChild(title);

        for (const ally of aliveAllies) {
            const btn = document.createElement('button');
            const allyName = ally.id === player.id ? selectedBrawler : (ally.brawler || 'ally');
            btn.textContent = allyName.toUpperCase();
            btn.style.border = 'none';
            btn.style.borderRadius = '999px';
            btn.style.padding = '6px 10px';
            btn.style.fontWeight = '800';
            btn.style.cursor = 'pointer';
            btn.style.background = '#5df2c2';
            btn.style.color = '#031019';
            btn.onclick = () => applyKnockDonateSuperDonation(entity, ally);
            overlay.appendChild(btn);
        }
        document.body.appendChild(overlay);
        knockDonateDonationUI = overlay;
    }

    function initBrickVaultModeState() {
        brickVaultTimer = 0;
        brickVaultWinnerTeam = null;
        brickVaultDamage = { player: 0, enemy: 0 };
        brickVaultTotalHp = {
            player: BRICK_VAULT_TIERS.reduce((sum, hp) => sum + hp, 0),
            enemy: BRICK_VAULT_TIERS.reduce((sum, hp) => sum + hp, 0),
        };

        const spawnVaultSet = (team, sideY) => {
            const xBands = [WORLD_W * 0.36, WORLD_W * 0.64];
            for (let i = 0; i < BRICK_VAULT_TIERS.length; i++) {
                const hp = BRICK_VAULT_TIERS[i];
                const w = 110;
                const h = 110;
                const dry = findNearestDrySpot(xBands[i], sideY, 60);
                destructibleWalls.push({
                    x: dry.x - w / 2,
                    y: dry.y - h / 2,
                    w,
                    h,
                    hp,
                    maxHp: hp,
                    ownerId: null,
                    isVault: true,
                    vaultTeam: team,
                    vaultTier: i + 1,
                });
            }
        };

        spawnVaultSet('player', WORLD_H * 0.88);
        spawnVaultSet('enemy', WORLD_H * 0.12);
    }

    function getArenaForgeSpawner(team) {
        return destructibleWalls.find((dw) => dw && dw.isArenaForgeSpawner && dw.spawnerTeam === team && dw.hp > 0) || null;
    }

    function getArenaForgeSpawnerTarget(team) {
        const enemyTeam = team === 'player' ? 'enemy' : 'player';
        const spawner = getArenaForgeSpawner(enemyTeam);
        if (!spawner) return null;
        return {
            x: spawner.x + spawner.w / 2,
            y: spawner.y + spawner.h / 2,
            id: 'forge_spawner',
            isArenaForgeSpawner: true,
        };
    }

    function initArenaForgeModeState() {
        arenaForgeTimer = 0;
        arenaForgeSoulBank = { player: 0, enemy: 0 };
        arenaForgeSouls = [];
        arenaForgeWaveIndex = 0;
        arenaForgeNextSoulAt = performance.now() + 900;
        const spawnSpawner = (team, y) => {
            const center = findNearestDrySpot(WORLD_W * 0.5, y, 60);
            const w = 140;
            const h = 120;
            destructibleWalls.push({
                x: center.x - w / 2,
                y: center.y - h / 2,
                w,
                h,
                hp: ARENA_FORGE_SPAWNER_HP,
                maxHp: ARENA_FORGE_SPAWNER_HP,
                ownerId: null,
                isArenaForgeSpawner: true,
                spawnerTeam: team,
                nextDefenseAt: performance.now() + 800,
            });
        };
        spawnSpawner('player', WORLD_H * 0.93);
        spawnSpawner('enemy', WORLD_H * 0.07);
    }

    function getBrickVaultWalls(team) {
        return destructibleWalls.filter((dw) => dw && dw.isVault && dw.vaultTeam === team && dw.hp > 0);
    }

    function getBrickVaultHealth(team) {
        return getBrickVaultWalls(team).reduce((sum, wall) => sum + Math.max(0, wall.hp), 0);
    }

    function getBrickVaultDamagePct(team) {
        const total = Math.max(1, brickVaultTotalHp[team] || 1);
        const dealt = Math.max(0, brickVaultDamage[team] || 0);
        return clamp(dealt / total, 0, 1);
    }

    function getBrickVaultTarget(team) {
        const enemyTeam = team === 'player' ? 'enemy' : 'player';
        const enemyVaults = getBrickVaultWalls(enemyTeam);
        if (!enemyVaults.length) return null;
        let best = enemyVaults[0];
        let bestHp = best.hp || 0;
        for (const wall of enemyVaults) {
            if ((wall.hp || 0) < bestHp) {
                best = wall;
                bestHp = wall.hp || 0;
            }
        }
        return {
            x: best.x + best.w / 2,
            y: best.y + best.h / 2,
            id: 'vault',
            isVault: true,
        };
    }

    function registerBrickVaultWallDamage(ownerId, wall, dealtDamage) {
        if (!isBrickVaultMode || !wall || !wall.isVault || dealtDamage <= 0) return;
        const owner = ownerId === player.id ? player : bots.find(bt => bt.id === ownerId);
        const ownerTeam = owner?.team || (ownerId === player.id ? 'player' : 'enemy');
        if (!ownerTeam || ownerTeam === wall.vaultTeam) return;
        brickVaultDamage[ownerTeam] = (brickVaultDamage[ownerTeam] || 0) + dealtDamage;
    }

    function getVaultDamagePerHit(rawDamage, wall) {
        if (!wall || !wall.isVault) return Math.max(1, rawDamage || 0);
        const safeRaw = Number.isFinite(rawDamage) ? rawDamage : 0;
        const tierMax = Math.max(1, wall.maxHp || wall.hp || 1);
        const pctCap = Math.max(1, tierMax * BRICK_VAULT_MAX_HIT_PCT);
        const cap = Math.max(1, Math.min(BRICK_VAULT_MAX_HIT_FLAT, pctCap));
        return clamp(safeRaw, 1, cap);
    }

    function applyProjectileEndpointVaultDamage(projectile) {
        if (!isBrickVaultMode || !projectile || (projectile.damage || 0) <= 0) return;
        if (projectile.ownerId === undefined || projectile.ownerId === null) return;
        const owner = projectile.ownerId === player.id ? player : bots.find(bt => bt.id === projectile.ownerId);
        const ownerTeam = owner?.team || (projectile.ownerId === player.id ? 'player' : 'enemy');
        const mult = 1.0 + ((owner ? owner.powerCubes : 0) || 0) * 0.1;
        const impactRadius = Math.max(5, (projectile.super ? 8 : 5) * (projectile.hitboxMod || 1));

        for (let wIdx = destructibleWalls.length - 1; wIdx >= 0; wIdx--) {
            const dw = destructibleWalls[wIdx];
            if (!dw || !dw.isVault || dw.hp <= 0) continue;
            if (ownerTeam === dw.vaultTeam) continue;
            if (!rectCircleCollides(dw.x, dw.y, dw.w, dw.h, projectile.x, projectile.y, impactRadius)) continue;
            const wallRawDmg = Math.max(0, (projectile.damage || 0) * mult);
            const wallDmg = Math.min(dw.hp, getVaultDamagePerHit(wallRawDmg, dw));
            if (wallDmg <= 0) continue;
            dw.hp -= wallDmg;
            registerBrickVaultWallDamage(projectile.ownerId, dw, wallDmg);
            if (dw.hp <= 0) destructibleWalls.splice(wIdx, 1);
        }
    }

    function getBotCombatStopDistance(bot, target) {
        if (!bot || !target || target.isPowerup || target.isBox) return 0;
        const brawlerId = bot.brawler || 'outlit';
        if (brawlerId === 'parrot') return 190;
        if (brawlerId === 'skeletrooper') return 30;
        if (brawlerId === 'evil_doctor_dna') return 20;
        if (brawlerId === 'dashaholic' || brawlerId === 'bowlin_rida' || brawlerId === 'beast') return 90;

        const role = String((brawlerData[brawlerId]?.role || '')).toLowerCase();
        if (role.includes('marksman') || role.includes('thrower')) return 300;
        if (role.includes('controller')) return 240;
        if (role.includes('support')) return 210;
        if (role.includes('assassin')) return 130;
        if (role.includes('tank') || role.includes('close-range')) return 120;
        return 180;
    }

    function drawStandardAimCone(originX, originY, angle, range, halfAngle, colors = {}) {
        const fill = colors.fill || 'rgba(170, 220, 255, 0.16)';
        const stroke = colors.stroke || 'rgba(210, 240, 255, 0.85)';
        const center = colors.center || 'rgba(255, 255, 255, 0.75)';
        ctx.save();
        ctx.fillStyle = fill;
        ctx.beginPath();
        ctx.moveTo(originX, originY);
        ctx.arc(originX, originY, range, angle - halfAngle, angle + halfAngle);
        ctx.closePath();
        ctx.fill();
        ctx.strokeStyle = stroke;
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(originX, originY);
        ctx.arc(originX, originY, range, angle - halfAngle, angle + halfAngle);
        ctx.closePath();
        ctx.stroke();
        ctx.strokeStyle = center;
        ctx.beginPath();
        ctx.moveTo(originX, originY);
        ctx.lineTo(originX + Math.cos(angle) * range, originY + Math.sin(angle) * range);
        ctx.stroke();
        ctx.restore();
    }

    function carveWaterNavigationLanes() {
        const verticalGap = 240;
        const horizontalGap = 240;
        const x1 = WORLD_W * 0.5 - verticalGap * 0.5;
        const x2 = WORLD_W * 0.5 + verticalGap * 0.5;
        const y1 = WORLD_H * 0.5 - horizontalGap * 0.5;
        const y2 = WORLD_H * 0.5 + horizontalGap * 0.5;

        const subtractVerticalStrip = (rect, minX, maxX) => {
            const rx1 = rect.x;
            const rx2 = rect.x + rect.w;
            if (rx2 <= minX || rx1 >= maxX) return [rect];
            const out = [];
            if (rx1 < minX) out.push({ x: rx1, y: rect.y, w: minX - rx1, h: rect.h });
            if (rx2 > maxX) out.push({ x: maxX, y: rect.y, w: rx2 - maxX, h: rect.h });
            return out;
        };

        const subtractHorizontalStrip = (rect, minY, maxY) => {
            const ry1 = rect.y;
            const ry2 = rect.y + rect.h;
            if (ry2 <= minY || ry1 >= maxY) return [rect];
            const out = [];
            if (ry1 < minY) out.push({ x: rect.x, y: ry1, w: rect.w, h: minY - ry1 });
            if (ry2 > maxY) out.push({ x: rect.x, y: maxY, w: rect.w, h: ry2 - maxY });
            return out;
        };

        const carved = [];
        for (const zone of waterZones) {
            let parts = [zone];
            const afterVertical = [];
            for (const part of parts) {
                afterVertical.push(...subtractVerticalStrip(part, x1, x2));
            }
            parts = afterVertical;
            const afterHorizontal = [];
            for (const part of parts) {
                afterHorizontal.push(...subtractHorizontalStrip(part, y1, y2));
            }
            carved.push(...afterHorizontal.filter((p) => p.w > 4 && p.h > 4));
        }

        waterZones.length = 0;
        waterZones.push(...carved);
    }

