  function generateCubes(){
    cubes.length = 0;
    bushZones.length = 0;
    waterZones.length = 0;
    malakorHellZones.length = 0;
    malakorHands.length = 0;
        if (isWarperEvent) {
            buildWarperArena();
            return;
        }
    if (!isBossFight && !isDuels && !isTraining && !isSoloTrial) {
        if (isMirrorMode) {
            buildMirrorMap();
            return;
        }
        if (isBrickVaultMode) {
            buildBrickVaultMap();
            return;
        }
        if (isArenaForgeMode) {
            cubes.length = 0;
            bushZones.length = 0;
            waterZones.length = 0;
            destructibleWalls.length = 0;
            return;
        }
        if (isDamageFillerMode || isKnockDonateMode) {
            buildDamageFillerMap();
            return;
        }
        if (isConstructionMode) {
            buildConstructionMap(getActiveConstructionMapIndex());
            return;
        }
        if (isPowerGodsMode) {
            cubes.length = 0;
            bushZones.length = 0;
            waterZones.length = 0;
            destructibleWalls.length = 0;
            return;
        }
        buildHandmadeShowdownMap(getActiveShowdownMapIndex());
        return;
    }
    const count = 40; // more cubes in large map
    for(let i=0;i<count;i++){
      const w = 64 + Math.floor(Math.random()*128);
      const h = 64 + Math.floor(Math.random()*128);
      let x,y,tries=0;
      do{
        x = 100 + Math.random()*(WORLD_W-200-w);
        y = 100 + Math.random()*(WORLD_H-200-h);
        tries++;
      } while(
          (
              (isBossFight && (rectCircleCollides(x,y,w,h, 1200,800, 250) || rectCircleCollides(x,y,w,h, 1200,2000, 250))) ||
              (isDuels && (rectCircleCollides(x,y,w,h, 200,750, 150) || rectCircleCollides(x,y,w,h, 1400,750, 150))) ||
              (!isBossFight && !isDuels && rectCircleCollides(x,y,w,h, 2000,2000, 300))
          ) && tries < 50
      );
      cubes.push({ x,y,w,h });
    }
  }

