  function triggerExplosion(x, y, damage, radius, isPlayerOwned) {
      AOEDamage(x, y, radius, damage, isPlayerOwned ? player.id : null, true);
      explosions.push({x: x, y: y, radius: radius, life: 0, maxLife: 0.2, color: 'rgba(173, 255, 47, 0.6)'});
      if (isPlayerOwned) { screenShakeUntil = performance.now() + 100; screenShakeAmount = 5; }
  }

  function triggerFightnFireImpact(projectile, shardImpact = false) {
      const ownerId = projectile.ownerId;
      const isPlayerOwned = ownerId === player.id;
      const damage = Math.max(1, Math.round(projectile.damage || (isPlayerOwned ? 900 : 750)));
      const centerRadius = shardImpact ? 60 : (projectile.superBurst ? 88 : 92);
      triggerExplosion(projectile.x, projectile.y, damage, centerRadius, isPlayerOwned);

      if (!shardImpact) {
          const shardCount = projectile.fightnFireShardCount || 4;
          const shardDamage = Math.max(1, Math.round(damage * (projectile.superBurst ? 0.45 : 0.6)));
          const baseOffset = shardCount === 4 ? Math.PI / 4 : 0;
          for (let i = 0; i < shardCount; i++) {
              const ang = baseOffset + (Math.PI * 2 * i) / shardCount;
              bullets.push({
                  ownerBrawler: 'fightnfire',
                  isFightnFireShard: true,
                  x: projectile.x,
                  y: projectile.y,
                  vx: Math.cos(ang) * 760 * 0.6,
                  vy: Math.sin(ang) * 760 * 0.6,
                  life: 0,
                  maxLife: projectile.superBurst ? 1.15 : 0.85,
                  dieAt: performance.now() + (projectile.superBurst ? 1150 : 850),
                  damage: shardDamage,
                  pierce: false,
                  hyperVisual: projectile.hyperVisual,
                  ownerId: ownerId,
                  superBurst: !!projectile.superBurst,
                  fightnFireBounced: false,
                  canBounce: !projectile.superBurst,
                  homingRadius: 0,
                  homingStrength: 0,
                  bounceDmgLoss: 0,
                  bounceLifeLoss: 0,
                  hitIds: {},
                  hitboxMod: 1.2,
                  shardOriginX: projectile.x,
                  shardOriginY: projectile.y,
                  shardMaxDist: projectile.hyperVisual ? 600 : 0,
                  birthTime: performance.now()
              });
          }
      }
  }

    function getBlobertStoredLiquid(entity) {
        return clamp(Math.floor(entity?.blobertStoredLiquid || 0), 0, 12);
    }

    function fireBlobertSuperJar(entity, ang, isHyper, starChoice) {
        const stored = getBlobertStoredLiquid(entity);
        const powerStacks = Math.min(stored, 10);
        const baseDamage = 1100 + powerStacks * 110 + (isHyper ? 220 : 0);
        const speed = 950 * 0.6 * (1 + powerStacks * 0.015);
        const radiusScale = 1 + powerStacks * 0.03 + (isHyper ? 0.08 : 0);
        const life = 1.2 + powerStacks * 0.03;
        bullets.push({
            ownerBrawler: 'goonbob',
            isGoonJar: true,
            x: entity.x,
            y: entity.y,
            vx: Math.cos(ang) * speed,
            vy: Math.sin(ang) * speed,
            life: 0,
            maxLife: life,
            damage: Math.round(baseDamage),
            pierce: false,
            hyperVisual: !!isHyper,
            ownerId: entity.id,
            super: true,
            jarStacks: powerStacks,
            jarRadiusScale: radiusScale
        });

        if (starChoice === 'long' && powerStacks > 0) {
            doHeal(entity, 220 * powerStacks, entity.id);
        }
        entity.blobertStoredLiquid = 0;
        explosions.push({
            x: entity.x,
            y: entity.y,
            radius: 30 + powerStacks * 2,
            life: 0,
            maxLife: 0.2,
            color: isHyper ? 'rgba(214, 86, 255, 0.62)' : 'rgba(173, 255, 47, 0.5)'
        });
    }

