                    bullets.push({ ownerBrawler: 'bouncin_balls', x: player.x, y: player.y, vx: Math.cos(ang + spread) * 1100 * 0.7, vy: Math.sin(ang + spread) * 1100 * 0.7, life: 0, maxLife: 2.8 * (player.bouncyBallsCrystalHyper ? 1.3 : 1.0), damage: 550, pierce: true, hyperVisual: true, ownerId: player.id, super: true, canBounce: true, bounceDmgLoss: 0, bounceLifeLoss: 0, ownerSp2: true, splitOnHit: true, hitIds: {}, hitboxMod: 2.0 });
