  duoShowdownBtn.style.padding = '10px 14px';
  duoShowdownBtn.style.borderRadius = '10px';
  duoShowdownBtn.style.border = 'none';
  duoShowdownBtn.style.fontWeight = '700';
  duoShowdownBtn.style.cursor = 'pointer';

    const objectiveShowdownBtn = document.createElement('button');
