  function buildSoloTrialMultilevelArena() {
      WORLD_W = 2400;
      WORLD_H = 2400;
      cubes.length = 0;
      powerups.length = 0;
    amplifierToolboxes.length = 0;
    amplifierScrewZones.length = 0;
    skeleParachutes.length = 0;
    skelePortals.length = 0;
    bushZones.length = 0;
    waterZones.length = 0;
      destructibleWalls.length = 0;
      soloTrialWaveWalls = {}; // Track walls by wave for destruction

      // Ladder steps - progressively getting narrower from bottom to top
      const ladderSteps = [
          { x: 140, y: 2060, w: 2120 },   // Step 1: widest (bottom)
          { x: 200, y: 1870, w: 2000 },   // Step 2
          { x: 280, y: 1680, w: 1840 },   // Step 3
          { x: 360, y: 1490, w: 1680 },   // Step 4
          { x: 460, y: 1300, w: 1480 },   // Step 5
          { x: 560, y: 1110, w: 1280 },   // Step 6
          { x: 680, y: 920, w: 1040 },    // Step 7
          { x: 800, y: 730, w: 800 },     // Step 8
          { x: 920, y: 540, w: 560 },     // Step 9
          { x: 1020, y: 350, w: 360 },    // Step 10
          { x: 1100, y: 160, w: 200 },    // Step 11: narrowest (top)
      ];

      // Create permanent border walls for each step.
      // Only the thin gate above each platform breaks after the wave is won.
      ladderSteps.forEach((step, idx) => {
          destructibleWalls.push({
              x: step.x,
              y: step.y,
              w: step.w,
              h: 44,
              hp: 9999,
              maxHp: 9999,
              ownerId: null,
              isSoloStep: true,
              isArenaBorder: true,
          });

          destructibleWalls.push({
              x: step.x - 38,
              y: step.y - 116,
              w: 42,
              h: 232,
              hp: 9999,
              maxHp: 9999,
              ownerId: null,
              isSoloStep: true,
              isArenaBorder: true,
          });

          destructibleWalls.push({
              x: step.x + step.w - 4,
              y: step.y - 116,
              w: 42,
              h: 232,
              hp: 9999,
              maxHp: 9999,
              ownerId: null,
              isSoloStep: true,
              isArenaBorder: true,
          });

          if (idx < ladderSteps.length - 1) {
              const gateWidth = Math.max(140, Math.min(280, step.w - 220));
              const gateX = step.x + Math.floor((step.w - gateWidth) / 2);
              const gate = {
                  x: gateX,
                  y: step.y - 96,
                  w: gateWidth,
                  h: 34,
                  hp: 9999,
                  maxHp: 9999,
                  ownerId: null,
                  isSoloStep: true,
                  isSoloGate: true,
                  breakAfterWave: idx + 1,
              };
              destructibleWalls.push(gate);
              soloTrialWaveWalls[idx + 1] = gate;
          }
      });
  }

  function spawnSoloTrialWave() {
      const wave = soloTrialWave + 1;
      soloTrialWave = wave;
      soloTrialPending = false;
      bots.length = 0;

      const trialBrawler = allBrawlers[(wave - 1) % allBrawlers.length];
      const tier = getHPTier(trialBrawler, clamp(wave, 1, SOLO_TRIAL_MAX_WAVES));
      const spawnY = 2060 - ((wave - 1) * 190);
      const spawnX = (wave % 2 === 1) ? 1840 : 560;

      bots.push({
          id: nextId++, x: spawnX, y: spawnY, baseX: spawnX, baseY: spawnY, z:0, vx:0, vy:0,
          hp: Math.round(tier.hp * (1.0 + wave * 0.15)), maxHp: Math.round(tier.hp * (1.0 + wave * 0.15)), powerCubes: wave, isDead: false,
          shield:0, shieldMax:0, shieldDecayTimer:0, reloadBuffUntil:0, radius: 18, speed: Math.max(60, tier.speed * 0.58),
          slowUntil:0, brawler: trialBrawler, lastTargetId: null, targetLockUntil: 0, lastShot: 0,
          superCharge: 0, hyperChargeCharge: 0, isHypercharged: false, hyperchargeUntil: 0, gadgetArmed: false,
          gadgetCooldownUntil: 0, selectedStar: wave % 2 === 0 ? 'long' : 'slow', unopcolocoCycle: 0, ridaSpeedMult: 1.0, ridaHitCooldowns: {},
          isFlying: false, isDummy: false, isSoloTrialBot: true, moneyAndTaxMode: 'money'
      });
  }

    // Legacy event buttons removed from home menu.
    const DEMON_ORIGIN_WATCH_KEY = 'brawl_arena_demon_origin_watched_v2';
    function openDemonOriginCinematic(opts = {}) {
        if (document.getElementById('demon-origin-overlay')) return;
        const markWatched = opts.markWatched !== false;
        const overlay = document.createElement('div');
        overlay.id = 'demon-origin-overlay';
        overlay.style.position = 'fixed';
        overlay.style.inset = '0';
        overlay.style.background = 'radial-gradient(circle at 50% 12%, rgba(140,0,0,0.3), rgba(6,5,10,0.98) 52%)';
        overlay.style.zIndex = '2600';
        overlay.style.display = 'flex';
        overlay.style.flexDirection = 'column';
        overlay.style.alignItems = 'center';
        overlay.style.justifyContent = 'center';
        overlay.style.padding = '14px';
        overlay.style.color = '#fff';
        overlay.style.fontFamily = 'Trebuchet MS, sans-serif';

        const title = document.createElement('div');
        title.textContent = 'MALAKOR ORIGIN: RED STAFF';
        title.style.fontSize = '28px';
        title.style.fontWeight = '900';
        title.style.letterSpacing = '0.06em';
        title.style.color = '#ffb2b2';
        title.style.marginBottom = '12px';

        const sub = document.createElement('div');
        sub.style.fontSize = '16px';
        sub.style.fontWeight = '700';
        sub.style.color = '#ffe4d8';
        sub.style.marginBottom = '10px';
        sub.style.textAlign = 'center';

        const canvas = document.createElement('canvas');
        canvas.width = 980;
        canvas.height = 520;
        canvas.style.width = 'min(96vw, 980px)';
        canvas.style.maxHeight = '58vh';
        canvas.style.border = '2px solid rgba(255,120,120,0.8)';
        canvas.style.borderRadius = '12px';
        canvas.style.background = '#09070d';
        canvas.style.boxShadow = '0 0 34px rgba(255,64,64,0.3)';
        const ctx = canvas.getContext('2d');

        const controls = document.createElement('div');
        controls.style.display = 'flex';
        controls.style.gap = '12px';
        controls.style.marginTop = '12px';

        const replayHint = document.createElement('div');
        replayHint.textContent = 'Witness the birth of Malakor...';
        replayHint.style.color = '#ff9999';
        replayHint.style.fontWeight = '800';
        replayHint.style.letterSpacing = '0.04em';
        replayHint.style.marginTop = '8px';

        const closeBtn = document.createElement('button');
        closeBtn.textContent = 'Skip';
        closeBtn.style.padding = '10px 18px';
        closeBtn.style.borderRadius = '10px';
        closeBtn.style.border = 'none';
        closeBtn.style.background = '#ff5a5a';
        closeBtn.style.color = '#210707';
        closeBtn.style.fontWeight = '900';
        closeBtn.style.cursor = 'pointer';

        const doneBtn = document.createElement('button');
        doneBtn.textContent = 'Close';
        doneBtn.style.padding = '10px 18px';
        doneBtn.style.borderRadius = '10px';
        doneBtn.style.border = '1px solid #ffbcbc';
        doneBtn.style.background = '#1e1120';
        doneBtn.style.color = '#ffd4d4';
        doneBtn.style.fontWeight = '900';
        doneBtn.style.cursor = 'pointer';
        doneBtn.style.display = 'none';

        controls.appendChild(closeBtn);
        controls.appendChild(doneBtn);
        overlay.appendChild(title);
        overlay.appendChild(sub);
        overlay.appendChild(canvas);
        overlay.appendChild(controls);
        overlay.appendChild(replayHint);
        document.body.appendChild(overlay);

        const scenes = [
            { text: 'A lonely kid touched a cursed red staff...', duration: 2600, bg: '#0b0d14', accent: '#8cc7ff' },
            { text: 'The staff struck him. Darkness branded his soul.', duration: 2200, bg: '#1a0d12', accent: '#ff5d5d' },
            { text: 'Years later, he bent demonic power to his will.', duration: 2600, bg: '#13070d', accent: '#ff7a7a' },
            { text: 'Now MALAKOR comes to drag the arena into hell.', duration: 3200, bg: '#190406', accent: '#ff3333' },
        ];
        const totalDuration = scenes.reduce((n, s) => n + s.duration, 0);
        let raf = 0;
        const startTime = performance.now();
        let finished = false;

        const closeOverlay = () => {
            if (markWatched) localStorage.setItem(DEMON_ORIGIN_WATCH_KEY, '1');
            if (overlay.isConnected) overlay.remove();
            if (raf) cancelAnimationFrame(raf);
        };
        closeBtn.onclick = closeOverlay;
        doneBtn.onclick = closeOverlay;
        overlay.onclick = (ev) => { if (ev.target === overlay) closeOverlay(); };

        function draw(nowTs) {
            if (!ctx || !overlay.isConnected) return;
            const elapsed = nowTs - startTime;
            let t = elapsed;
            let idx = 0;
            while (idx < scenes.length - 1 && t > scenes[idx].duration) {
                t -= scenes[idx].duration;
                idx += 1;
            }
            const scene = scenes[Math.min(idx, scenes.length - 1)];
            const p = Math.max(0, Math.min(1, t / scene.duration));

            ctx.clearRect(0, 0, canvas.width, canvas.height);
            const grad = ctx.createLinearGradient(0, 0, 0, canvas.height);
            grad.addColorStop(0, scene.bg);
            grad.addColorStop(1, '#040207');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            for (let i = 0; i < 10; i++) {
                const x = ((nowTs * 0.02 + i * 120) % (canvas.width + 140)) - 70;
                const y = 110 + i * 46 + Math.sin(nowTs * 0.0014 + i) * 9;
                ctx.fillStyle = `rgba(255, 70, 70, ${0.05 + i * 0.01})`;
                ctx.fillRect(x, y, 62, 6);
            }

            // Rift lightning to make the cinematic feel heavier.
            if (scene.accent !== '#8cc7ff') {
                const boltCount = 3;
                for (let b = 0; b < boltCount; b++) {
                    const sx = 120 + b * 320 + Math.sin((nowTs + b * 80) / 170) * 30;
                    const sy = 40;
                    let px = sx;
                    let py = sy;
                    ctx.beginPath();
                    ctx.moveTo(px, py);
                    for (let step = 0; step < 8; step++) {
                        px += (Math.random() * 36) - 18;
                        py += 32 + Math.random() * 18;
                        ctx.lineTo(px, py);
                    }
                    ctx.strokeStyle = 'rgba(255, 90, 90, 0.25)';
                    ctx.lineWidth = 2;
                    ctx.stroke();
                }
            }

            const kidX = 180 + Math.min(1, elapsed / 2500) * 120;
            const heroScale = 0.9 + Math.min(1, Math.max(0, (elapsed - 4000) / 4500)) * 0.55;
            ctx.save();
            ctx.translate(kidX, 350);
            ctx.scale(heroScale, heroScale);
            ctx.fillStyle = '#1d1d28';
            ctx.fillRect(-18, -70, 36, 70);
            ctx.beginPath();
            ctx.arc(0, -85, 18, 0, Math.PI * 2);
            ctx.fillStyle = '#f3d6bf';
            ctx.fill();
            ctx.restore();

            const staffX = 500 + Math.sin(nowTs * 0.004) * 30;
            ctx.save();
            ctx.translate(staffX, 220);
            ctx.rotate(-0.25 + Math.sin(nowTs * 0.005) * 0.12);
            ctx.fillStyle = '#7d0505';
            ctx.fillRect(-8, -105, 16, 210);
            ctx.beginPath();
            ctx.arc(0, -108, 16, 0, Math.PI * 2);
            ctx.fillStyle = '#ff2f2f';
            ctx.fill();
            ctx.restore();

            const pulseStrength = (scene.accent === '#ff5d5d' || scene.accent === '#ff3333') ? (0.4 + Math.sin(nowTs * 0.02) * 0.25) : 0.12;
            ctx.strokeStyle = `rgba(255,80,80,${pulseStrength})`;
            ctx.lineWidth = 6;
            ctx.beginPath();
            ctx.arc(staffX, 220, 42 + Math.sin(nowTs * 0.01) * 14, 0, Math.PI * 2);
            ctx.stroke();

            ctx.fillStyle = scene.accent;
            ctx.font = 'bold 38px Trebuchet MS';
            ctx.textAlign = 'center';
            ctx.fillText(scene.text, canvas.width * 0.5, 454);

            if (idx === scenes.length - 1) {
                ctx.font = '900 64px Trebuchet MS';
                ctx.fillStyle = `rgba(255, 70, 70, ${0.35 + Math.sin(nowTs / 110) * 0.2})`;
                ctx.fillText('MALAKOR', canvas.width * 0.5, 120);
            }

            ctx.fillStyle = 'rgba(255,255,255,0.16)';
            ctx.fillRect(32, 486, canvas.width - 64, 10);
            const progress = Math.max(0, Math.min(1, elapsed / totalDuration));
            ctx.fillStyle = '#ff5555';
            ctx.fillRect(32, 486, (canvas.width - 64) * progress, 10);

            sub.textContent = `Scene ${Math.min(idx + 1, scenes.length)}/${scenes.length}`;

            if (elapsed >= totalDuration) {
                finished = true;
                closeBtn.style.display = 'none';
                doneBtn.style.display = 'inline-block';
                replayHint.textContent = 'Malakor has awakened.';
                return;
            }
            raf = requestAnimationFrame(draw);
        }

        raf = requestAnimationFrame(draw);
    }

