              ctx.strokeStyle = 'rgba(255, 255, 0, 0.6)'; ctx.lineWidth = 2; ctx.strokeRect(b.x - (b.isStickySuper ? 13 : 8), b.y - (b.isStickySuper ? 8 : 5), b.isStickySuper ? 26 : 16, b.isStickySuper ? 16 : 10);
